import React, { useEffect, useRef } from 'react';
import { Card } from '../ui/Shared';
import { KPI_DATA } from '../../data/mockData';
import { Trees, CloudFog, Flame, ArrowUpRight, ArrowDownRight, Info, AlertOctagon, CheckCircle2, AlertTriangle } from 'lucide-react';
import { cn } from '../../lib/utils';

export const KpiCards = ({ countryCode = 'Regional', highlightKey = null }) => {
    const data = countryCode === 'Regional' ? KPI_DATA.regional : (KPI_DATA.byCountry[countryCode] || KPI_DATA.regional);
    const highlightRef = useRef(null);

    // Scroll to highlighted card if present
    useEffect(() => {
        if (highlightRef.current) {
            highlightRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }, [highlightKey]);

    // Helper to format numbers safely
    const fmt = (n) => n ? new Intl.NumberFormat('es-ES').format(n) : '0';

    const getStatusIcon = (status) => {
        switch (status) {
            case 'success': return <CheckCircle2 className="h-5 w-5 text-green-500" />;
            case 'warning': return <AlertTriangle className="h-5 w-5 text-yellow-500" />;
            case 'danger': return <AlertOctagon className="h-5 w-5 text-red-500" />;
            default: return null;
        }
    };

    const getStatusColor = (status) => {
        switch (status) {
            case 'success': return "bg-green-100/50 border-green-200 text-green-800";
            case 'warning': return "bg-yellow-100/50 border-yellow-200 text-yellow-800";
            case 'danger': return "bg-red-100/50 border-red-200 text-red-800";
            default: return "bg-slate-100 text-slate-800";
        }
    };

    const cards = [
        {
            key: 'forestCover',
            title: "Cobertura Boscosa",
            value: fmt(data.forestCover.value),
            unit: data.forestCover.unit,
            icon: Trees,
            color: "text-green-600",
            bgColor: "bg-green-50",
            trend: data.forestCover.trend,
            trendValue: `${Math.abs(data.forestCover.change)}% anual`,
            status: data.forestCover.status || 'warning',
            meta: data.forestCover
        },
        {
            key: 'emissions',
            title: "Emisiones CO2e",
            value: fmt(data.emissions.value),
            unit: "tCO2e (AFOLU)",
            icon: CloudFog,
            color: "text-blue-600",
            bgColor: "bg-blue-50",
            trend: data.emissions.trend,
            trendValue: `${Math.abs(data.emissions.change)}% vs año ant.`,
            status: data.emissions.status || 'danger',
            meta: data.emissions
        },
        {
            key: 'fireAlerts',
            title: "Alertas de Incendio",
            value: fmt(data.fireAlerts.value),
            unit: "VIIRS (24h)",
            icon: Flame,
            color: "text-red-600",
            bgColor: "bg-red-50",
            trend: data.fireAlerts.trend,
            trendValue: `+${data.fireAlerts.change}% vs ayer`,
            status: data.fireAlerts.status || 'danger',
            meta: data.fireAlerts
        },
        {
            key: 'restoration', // Ensuring key exists in mockData or defaulting
            title: "Restauración",
            value: fmt(data.restoration?.value || 0),
            unit: "Hectáreas",
            icon: Trees,
            color: "text-emerald-600",
            bgColor: "bg-emerald-50",
            trend: data.restoration?.trend || 'up',
            trendValue: `Avance Meta 2030`,
            status: data.restoration?.status || 'success',
            meta: data.restoration
        }
    ];

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-6">
            {cards.map((card, idx) => {
                const isHighlighted = highlightKey && card.key === highlightKey;

                return (
                    <Card
                        key={idx}
                        ref={isHighlighted ? highlightRef : null}
                        className={cn(
                            "relative overflow-hidden hover:shadow-md transition-all duration-300 group",
                            isHighlighted ? "ring-2 ring-brand-primary scale-105 shadow-xl" : ""
                        )}
                    >
                        {/* Metadata Tooltip (Simulated on Hover/Click via Popover logic would be better but this is MVP) */}
                        <div className="absolute top-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
                            <div title={`Fuente: ${card.meta?.source}\nMétodo: ${card.meta?.method}\nActualizado: ${card.meta?.updated}`} className="cursor-help text-slate-300 hover:text-brand-primary">
                                <Info className="h-4 w-4" />
                            </div>
                        </div>

                        <div className="flex justify-between items-start mb-4">
                            <div className={cn("p-2 rounded-lg", card.bgColor)}>
                                <card.icon className={cn("h-6 w-6", card.color)} />
                            </div>
                            <div className={cn("px-2 py-1 rounded-full text-xs font-bold flex items-center gap-1 border", getStatusColor(card.status))}>
                                {getStatusIcon(card.status)}
                                {card.status === 'success' ? 'En Meta' : card.status === 'warning' ? 'Riesgo' : 'Crítico'}
                            </div>
                        </div>

                        <div>
                            <p className="text-sm font-medium text-slate-500 mb-1">{card.title}</p>
                            <h3 className="text-2xl font-bold text-slate-900 tracking-tight">{card.value}</h3>
                            <p className="text-xs text-slate-400 mt-1">{card.unit}</p>
                        </div>

                        <div className="mt-4 pt-3 border-t border-slate-100 flex items-center justify-between">
                            <div className={cn(
                                "flex items-center text-xs font-bold",
                                card.trend === 'up' && card.title !== 'Restauración' ? "text-red-500" : "text-emerald-600" // Logic tweak: Up is bad for emissions/fire, good for restoration
                            )}>
                                {card.trend === 'up' ? <ArrowUpRight className="h-3 w-3 mr-1" /> : <ArrowDownRight className="h-3 w-3 mr-1" />}
                                {card.trendValue}
                            </div>
                        </div>
                    </Card>
                );
            })}
        </div>
    );
};

import React, { useState, useMemo } from 'react';
import { DOCUMENTATION_DATA } from '../../data/documentation';
import { Card, Button, Input, Badge } from '../ui/Shared';
import { Search, FileText, Download, Eye, FileSpreadsheet, Map, Filter, Globe, BookOpen, Clock, ChevronDown, ExternalLink } from 'lucide-react';
import { cn } from '../../lib/utils';
import { SICA_COUNTRIES } from '../../data/constants';

export const DocSearch = ({ initialQuery = "" }) => {
    const [searchTerm, setSearchTerm] = useState(initialQuery);
    const [selectedCountry, setSelectedCountry] = useState('Todos');
    const [selectedAxis, setSelectedAxis] = useState('Todos');

    const axes = useMemo(() => {
        const allAxes = DOCUMENTATION_DATA.flatMap(doc => doc.ejes);
        return ['Todos', ...new Set(allAxes)];
    }, []);

    const countries = useMemo(() => {
        return ['Todos', 'Regional', ...SICA_COUNTRIES.map(c => c.name)];
    }, []);

    const filteredDocs = useMemo(() => {
        return DOCUMENTATION_DATA.filter(doc => {
            const matchesSearch = doc.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                doc.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
                doc.author.toLowerCase().includes(searchTerm.toLowerCase());
            
            const matchesCountry = selectedCountry === 'Todos' || doc.country === selectedCountry;
            const matchesAxis = selectedAxis === 'Todos' || doc.ejes.includes(selectedAxis);
            
            return matchesSearch && matchesCountry && matchesAxis;
        });
    }, [searchTerm, selectedCountry, selectedAxis]);

    const getIcon = (type) => {
        switch (type.toUpperCase()) {
            case 'PDF': return <FileText className="h-8 w-8 text-rose-500" />;
            case 'EXCEL': return <FileSpreadsheet className="h-8 w-8 text-emerald-500" />;
            case 'MAPA': return <Map className="h-8 w-8 text-blue-500" />;
            case 'ESTRATEGIA': return <BookOpen className="h-8 w-8 text-indigo-500" />;
            default: return <FileText className="h-8 w-8 text-slate-400" />;
        }
    };

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            {/* Header / Search Controls */}
            <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col gap-8">
                <div className="flex flex-col md:flex-row gap-6 items-center">
                    <div className="flex-1 w-full relative">
                        <Input
                            icon={Search}
                            placeholder="Buscar por título, autor o palabras clave..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="h-14 text-lg shadow-inner bg-slate-50 border-none rounded-2xl"
                        />
                    </div>
                </div>

                <div className="flex flex-wrap gap-4 items-center border-t border-slate-50 pt-6">
                    <div className="flex items-center gap-2 text-slate-400 mr-2">
                        <Filter className="h-4 w-4" />
                        <span className="text-[10px] font-black uppercase tracking-widest">Filtros Avanzados</span>
                    </div>

                    <div className="flex flex-wrap gap-2">
                        <div className="relative">
                            <select 
                                value={selectedCountry}
                                onChange={(e) => setSelectedCountry(e.target.value)}
                                className="appearance-none bg-slate-50 border-none rounded-xl px-4 py-2 pr-10 text-xs font-bold text-slate-600 focus:ring-2 focus:ring-brand-primary outline-none transition-all cursor-pointer"
                            >
                                {countries.map(c => (
                                    <option key={c} value={c}>
                                        {c === 'Todos' ? 'Todos los Países' : c}
                                    </option>
                                ))}
                            </select>
                            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-slate-400 pointer-events-none" />
                        </div>

                        <div className="relative">
                            <select 
                                value={selectedAxis}
                                onChange={(e) => setSelectedAxis(e.target.value)}
                                className="appearance-none bg-slate-50 border-none rounded-xl px-4 py-2 pr-10 text-xs font-bold text-slate-600 focus:ring-2 focus:ring-brand-primary outline-none transition-all cursor-pointer"
                            >
                                {axes.map(a => (
                                    <option key={a} value={a}>
                                        {a === 'Todos' ? 'Todos los Ejes' : a}
                                    </option>
                                ))}
                            </select>
                            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-slate-400 pointer-events-none" />
                        </div>
                    </div>

                    <div className="ml-auto text-xs font-bold text-slate-400 bg-slate-50 px-4 py-2 rounded-full">
                        {filteredDocs.length} documentos encontrados
                    </div>
                </div>
            </div>

            {/* Grid of Docs */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {filteredDocs.map((doc) => (
                    <Card key={doc.id} className="group flex flex-col hover:shadow-2xl transition-all duration-500 rounded-[2.5rem] border-none shadow-sm overflow-hidden bg-white">
                        <div className="h-40 overflow-hidden relative">
                            <img 
                                src={doc.thumbnail || "https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&q=80&w=400"} 
                                alt={doc.name} 
                                className="w-full h-full object-cover grayscale opacity-60 group-hover:grayscale-0 group-hover:opacity-100 transition-all duration-700"
                            />
                            <div className="absolute inset-0 bg-gradient-to-t from-white to-transparent" />
                            
                            <div className="absolute top-4 left-4 flex gap-2">
                                <Badge className="bg-white/80 backdrop-blur-md text-slate-800 border-none text-[9px] font-black uppercase">
                                    {doc.type}
                                </Badge>
                                <Badge className="bg-brand-primary/80 backdrop-blur-md text-white border-none text-[9px] font-black uppercase">
                                    {doc.country}
                                </Badge>
                            </div>
                        </div>

                        <div className="px-8 pb-8 flex-grow flex flex-col -mt-12 relative z-10">
                            <div className="bg-white rounded-2xl p-4 shadow-lg mb-4 inline-flex self-start group-hover:scale-110 transition-transform duration-500">
                                {getIcon(doc.type)}
                            </div>

                            <h3 className="font-bold text-slate-900 text-lg mb-2 line-clamp-2 leading-tight group-hover:text-brand-primary transition-colors">
                                {doc.name}
                            </h3>

                            <p className="text-slate-500 text-xs font-medium leading-relaxed mb-4 line-clamp-3">
                                {doc.description}
                            </p>

                            <div className="flex flex-wrap gap-1.5 mb-6">
                                {doc.ejes.map((eje, idx) => (
                                    <span key={idx} className="text-[9px] font-black uppercase tracking-wider text-brand-primary/70 bg-brand-primary/5 px-2 py-0.5 rounded-md">
                                        {eje}
                                    </span>
                                ))}
                            </div>

                            {/* Versions Selector if more than 1, or just info */}
                            <div className="mt-auto space-y-4">
                                {doc.versions && doc.versions.length > 1 ? (
                                    <div className="bg-slate-50 rounded-xl p-3">
                                        <div className="flex items-center gap-2 mb-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                                            <Clock className="h-3 w-3" /> Historial de Versiones
                                        </div>
                                        <div className="space-y-1">
                                            {doc.versions.map((v, i) => (
                                                <button key={i} className="flex items-center justify-between w-full text-[11px] font-bold text-slate-600 hover:text-brand-primary py-1 transition-colors group/ver">
                                                    <span>{v.label} ({v.year})</span>
                                                    <Download className="h-3 w-3 opacity-0 group-hover/ver:opacity-100" />
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                ) : (
                                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50/50 p-2 rounded-lg">
                                        <Clock className="h-3 w-3" /> Actualizado: {doc.date}
                                    </div>
                                )}

                                <div className="flex gap-2 pt-4 border-t border-slate-50">
                                    <Button variant="primary" size="sm" className="flex-1 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg shadow-brand-primary/20">
                                        <Eye className="h-3.5 w-3.5 mr-2" />
                                        Ver Documento
                                    </Button>
                                    <Button variant="white" size="sm" className="px-3 rounded-full border-slate-100 hover:bg-slate-50 text-slate-400 hover:text-brand-primary transition-colors shadow-sm">
                                        <Download className="h-4 w-4" />
                                    </Button>
                                </div>
                            </div>
                        </div>
                    </Card>
                ))}

                {filteredDocs.length === 0 && (
                    <div className="col-span-full py-20 text-center bg-white rounded-[3rem] border-2 border-dashed border-slate-100 shadow-inner">
                        <div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
                            <Search className="h-10 w-10 text-slate-200" />
                        </div>
                        <h3 className="text-xl font-bold text-slate-800 mb-2">Sin resultados encontrados</h3>
                        <p className="text-slate-500 max-w-sm mx-auto font-light">
                            No encontramos documentos que coincidan con "{searchTerm}". Intenta ajustar tus filtros de búsqueda.
                        </p>
                        <Button 
                            variant="ghost" 
                            className="mt-6 text-brand-primary font-bold"
                            onClick={() => { setSearchTerm(''); setSelectedCountry('Todos'); setSelectedAxis('Todos'); }}
                        >
                            Limpiar todos los filtros
                        </Button>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Sphere, Torus, Float, PerspectiveCamera, Html, Preload, useTexture, Billboard } from '@react-three/drei';
import * as THREE from 'three';
import { useNavigate } from 'react-router-dom';
import { CaretLeft, CaretRight, Tree, Fish, CloudRain, Drop, Wind, WarningCircle, Bell, List, ArrowLeft, SpeakerHigh } from '@phosphor-icons/react';
import { cn } from '../../lib/utils';

// --- SISTEMA DE AUDIO REUTILIZABLE ---
const playSound = (isMuted) => {
    if (isMuted) return;
    const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    const osc = audioCtx.createOscillator();
    const gainNode = audioCtx.createGain();
    osc.connect(gainNode);
    gainNode.connect(audioCtx.destination);
    const now = audioCtx.currentTime;

    osc.type = 'sine';
    osc.frequency.setValueAtTime(600, now);
    osc.frequency.exponentialRampToValueAtTime(150, now + 0.15);
    gainNode.gain.setValueAtTime(0.05, now);
    gainNode.gain.exponentialRampToValueAtTime(0.001, now + 0.15);
    osc.start(now);
    osc.stop(now + 0.15);
};

const Node = ({ position, color, title, isActive, onClick }) => {
    const mesh = useRef();
    const mapTexture = useTexture('/ca_dr_silhouette.png'); // Load the map silhouette texture
    
    useFrame((state, delta) => {
        if (mesh.current) {
            mesh.current.rotation.x += delta * 0.2;
            mesh.current.rotation.y += delta * 0.2;
            
            const targetScale = isActive ? 1.9 : 1;
            mesh.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), 0.15);
        }
    });

    return (
        <group position={position}>
            <Sphere 
                ref={mesh} 
                args={[4.5, 32, 32]} 
                onClick={onClick}
            >
                <meshPhysicalMaterial 
                    color={color} 
                    metalness={0.1} 
                    roughness={0.1} 
                    transmission={isActive ? 0.4 : 0.7}
                    thickness={2} 
                    ior={1.4} 
                    emissive={color} 
                    emissiveIntensity={isActive ? 0.6 : 0.25}
                    transparent={true} 
                    opacity={isActive ? 0.9 : 0.6}
                />
            </Sphere>

            {/* Map Silhouette Core */}
            <Billboard follow={true}>
                <Float speed={3} rotationIntensity={0.2} floatIntensity={0.5}>
                    <mesh>
                        <planeGeometry args={[5.5, 5.5]} />
                        <meshBasicMaterial 
                            color={isActive ? "#ffffff" : color} 
                            map={mapTexture} 
                            transparent={true} 
                            opacity={isActive ? 1.0 : 0.4} 
                            blending={THREE.AdditiveBlending}
                            depthWrite={false}
                        />
                    </mesh>
                </Float>
            </Billboard>

            <Html center position={[0, isActive ? 11 : -9, 0]} zIndexRange={[100, 0]}>
                <div 
                    className={cn(
                        "pointer-events-none transition-all duration-500 whitespace-nowrap drop-shadow-[0_2px_6px_rgba(0,0,0,0.9)] flex items-center justify-center",
                        isActive 
                            ? "text-[#ffffff] text-[24px] font-bold tracking-[6px]" 
                            : "text-[#ffffff]/60 text-[11px] font-semibold tracking-[1px] uppercase"
                    )}
                    style={{ textShadow: isActive ? '0 0 20px rgba(255,255,255,0.4), 0 4px 12px rgba(0,0,0,0.9)' : undefined }}
                >
                    {isActive ? title.toUpperCase() : title.toUpperCase()}
                </div>
            </Html>
        </group>
    );
};

const OrbitBeams = ({ color }) => {
    return (
        <group>
            <Torus args={[55, 0.05, 16, 128]}>
                <meshBasicMaterial color="#2ecc71" transparent opacity={0.15} />
            </Torus>
            <Torus args={[55, 0.2, 16, 100]}>
                <meshBasicMaterial color={color} transparent opacity={0.05} />
            </Torus>
        </group>
    );
};

const CarouselRig = ({ axes, activeIndex, targetRotation, setIsDashboardOpen, isMuted, onNodeClick }) => {
    const groupRef = useRef();
    const radius = 55;
    const angleStep = (Math.PI * 2) / axes.length;
    
    useFrame((state, delta) => {
        if (groupRef.current) {
            // Rotación suave, continua y sin límites de cuadrante
            groupRef.current.rotation.z += (targetRotation - groupRef.current.rotation.z) * 0.15;
        }
    });

    return (
        <group position={[0, 0, 0]}>
            <group rotation={[Math.PI / 2.3, 0, 0]} ref={groupRef}>
                <OrbitBeams color={axes[activeIndex].color} />
                {axes.map((axis, i) => {
                    const angle = (Math.PI / 2) - (i * angleStep);
                    return (
                        <Node 
                            key={axis.id}
                            position={[Math.cos(angle) * radius, Math.sin(angle) * radius, 0]}
                            color={axis.color}
                            title={axis.text}
                            isActive={i === activeIndex}
                            onClick={(e) => {
                                e.stopPropagation();
                                onNodeClick(i);
                            }}
                        />
                    );
                })}
            </group>
        </group>
    );
};

export const Hero3D = ({ axes }) => {
    const [activeIndex, setActiveIndex] = useState(0);
    const [targetRotation, setTargetRotation] = useState(0);
    const [isDashboardOpen, setIsDashboardOpen] = useState(false);
    const [isMuted, setIsMuted] = useState(false);
    const navigate = useNavigate();

    const totalNodes = axes.length;
    const angleStep = (Math.PI * 2) / totalNodes;

    const handleNodeClick = (clickedIndex) => {
        if (clickedIndex === activeIndex) {
            setIsDashboardOpen(true);
        } else {
            // Calcular el camino más corto natural en términos de índices
            let diff = clickedIndex - activeIndex;
            
            // Si la distancia cruzando el círculo es menor, tomamos la ruta corta
            if (diff > totalNodes / 2) diff -= totalNodes;
            else if (diff < -totalNodes / 2) diff += totalNodes;
            
            setActiveIndex(clickedIndex);
            // La rotación suma para compensar el ángulo negativo del mapeo
            setTargetRotation((prev) => prev + (diff * angleStep));
            playSound(isMuted);
        }
    };

    return (
        <div className="relative w-full h-screen bg-[#021226] overflow-hidden">
            <div className="absolute inset-0 bg-gradient-to-b from-[#0f2847] via-[#0a221a] to-[#021226] z-0" />
            
            <Canvas dpr={[1, 2]}>
                <PerspectiveCamera 
                    makeDefault 
                    position={[0, 35, 130]} 
                    fov={45} 
                    onUpdate={c => c.lookAt(0, -10, 0)}
                />
                <fog attach="fog" args={['#133e36', 100, 220]} />
                
                <React.Suspense fallback={null}>
                    <hemisphereLight args={['#87CEEB', '#0984e3', 0.7]} />
                    <directionalLight color="#fff5e6" intensity={0.8} position={[30, 100, 30]} />
                    <pointLight color={axes[activeIndex].color} intensity={2.5} distance={120} position={[0, 0, 80]} />
                    
                    <CarouselRig 
                        axes={axes} 
                        activeIndex={activeIndex} 
                        targetRotation={targetRotation}
                        setIsDashboardOpen={setIsDashboardOpen} 
                        isMuted={isMuted} 
                        onNodeClick={handleNodeClick}
                    />
                    
                    <Preload all />
                </React.Suspense>
            </Canvas>

            {/* UI Layer */}
            <div className="absolute inset-0 pointer-events-none z-10">
                <div className="w-full h-full relative flex flex-col items-center">
                    
                    {/* Header institucional */}
                    <div className="mt-8 text-center animate-fade-in">
                        <h2 className="text-white text-lg font-bold tracking-[0.4em] uppercase opacity-90 drop-shadow-lg">
                            Observatorio Ambiental Regional
                        </h2>
                    </div>

                    {/* Descripcion Central */}
                    <div className={cn(
                        "mt-12 max-w-xl text-center transition-all duration-700 pointer-events-none",
                        isDashboardOpen ? "opacity-0 scale-90" : "opacity-100 scale-100"
                    )}>
                        <div className="relative p-6 rounded-3xl bg-white/5 backdrop-blur-sm border border-white/10 shadow-2xl overflow-hidden">
                            <div className="absolute inset-0 bg-gradient-to-r from-blue-500/10 to-emerald-500/10 opacity-50" />
                            <p className="text-slate-200 text-sm leading-relaxed relative z-10">
                                {axes[activeIndex].description}
                            </p>
                        </div>
                        
                        <div className="mt-8 pointer-events-auto">
                            <button 
                                onClick={() => setIsDashboardOpen(true)}
                                className="px-10 py-3 bg-white/10 hover:bg-white text-white hover:text-[#021226] font-bold text-xs uppercase tracking-[0.3em] rounded-full border border-white/20 transition-all shadow-xl backdrop-blur-md"
                            >
                                Ingresar al Eje
                            </button>
                        </div>
                    </div>

                    {/* Controls */}
                    <div className="absolute bottom-10 left-10 pointer-events-auto">
                        <button 
                            onClick={() => setIsMuted(!isMuted)}
                            className="w-10 h-10 rounded-full flex items-center justify-center bg-white/5 border border-white/10 text-white/50 hover:text-white transition-all backdrop-blur-sm"
                        >
                            <SpeakerHigh size={18} weight={isMuted ? "slash" : "fill"} />
                        </button>
                    </div>
                </div>
            </div>

            {/* dashboard View (Modal) */}
            <DashboardOverlay 
                isOpen={isDashboardOpen} 
                onClose={() => setIsDashboardOpen(false)} 
                axis={axes[activeIndex]} 
            />
        </div>
    );
};

