                        size="lg"
                        className="w-full sm:w-auto rounded-full px-10 py-4 font-black uppercase text-[11px] tracking-[0.2em] shadow-2xl shadow-brand-primary/30 hover:shadow-brand-primary/40 transition-all hover:-translate-y-0.5"
