            img: "/forests/dominican_republic.png",
            status: "Tesoro Antillano"
        },
    ];

    return (
        <div className="bg-slate-50 min-h-screen">
            {/* Modal for Bridges */}
            {selectedBridge && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                    <div 
                        className="absolute inset-0 bg-emerald-950/60 backdrop-blur-sm transition-opacity" 
                        onClick={() => setSelectedBridge(null)}
                    ></div>
                    
                    <div className="relative bg-white w-full max-w-4xl max-h-[90vh] rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in duration-300">
                        <button 
                            className="absolute top-6 right-6 z-10 p-2 rounded-full bg-black/20 text-white hover:bg-black/40 transition-colors"
                            onClick={() => setSelectedBridge(null)}
                        >
                            <X className="h-6 w-6" />
                        </button>
                        
                        <div className="md:flex-1 h-64 md:h-auto overflow-hidden">
                            <img 
                                src={selectedBridge.img} 
                                alt={selectedBridge.name} 
                                className="w-full h-full object-cover"
                            />
                        </div>
                        
                        <div className="md:flex-1 p-8 md:p-12 flex flex-col justify-center space-y-6">
                            <div className="space-y-2">
                                <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-100 text-emerald-700 text-xs font-bold uppercase tracking-wider">
                                    <Share2 className="h-3 w-3" /> Ecosistema Compartido
                                </div>
                                <h3 className="text-3xl md:text-4xl font-serif font-black text-slate-900 leading-tight">
                                    {selectedBridge.name}
                                </h3>
                            </div>
                            
                            <p className="text-lg text-slate-600 leading-relaxed font-light">
                                {selectedBridge.desc}
                            </p>
                            
                            <div className="space-y-3">
                                <h4 className="text-xs font-black uppercase tracking-widest text-slate-400">Países Participantes</h4>
                                <div className="flex flex-wrap gap-2">
                                    {selectedBridge.countries.map(c => (
                                        <div key={c} className="px-3 py-1.5 rounded-xl bg-slate-100 border border-slate-200 text-slate-700 text-sm font-bold">
                                            {c}
                                        </div>
                                    ))}
                                </div>
                            </div>
                            
                                <div className="flex flex-col sm:flex-row gap-4 pt-4">
                                    <Button 
                                        className="bg-emerald-500 hover:bg-emerald-600 rounded-2xl py-6 font-bold flex items-center justify-center gap-2"
                                        onClick={() => navigate(`/grandes-bosques/historias/${getSlug(selectedBridge.name)}`)}
                                    >
                                        Ver Historia Completa
                                    </Button>
                                    <Button 
                                        variant="outline"
                                        className="border-slate-200 text-slate-600 hover:bg-slate-50 rounded-2xl py-6 font-bold"
                                        onClick={() => setSelectedBridge(null)}
                                    >
                                        Cerrar Información
                                    </Button>
                                </div>
                        </div>
                    </div>
                </div>
            )}

            {/* Navigation removed as it's now handled by the main Layout */}

            {/* Page Header */}
            <div className="pt-8 px-8 pb-4">
                <div className="flex items-center gap-3 mb-2 text-emerald-600">
                    <Trees className="h-6 w-6" />
                    <span className="text-xs font-bold text-slate-500 uppercase tracking-widest text-emerald-600/70">Iniciativa Regional CCAD</span>
                </div>
                
                <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-6 pb-6 border-b border-slate-100">
                    <div className="space-y-2">
                        <h1 className="text-3xl md:text-4xl font-serif font-black text-slate-900 leading-tight mt-2">
                            Grandes Bosques de Centro América y República Dominicana
                        </h1>
                        <p className="text-lg text-slate-600 max-w-3xl leading-relaxed">
                            Una iniciativa para proteger los pulmones verdes de los países de la Región SICA, monitoreando la conectividad y la salud forestal.
                        </p>
                    </div>
                    
                    <div className="shrink-0">
                        <select 
                            className="bg-emerald-600 hover:bg-emerald-700 text-white px-6 py-3 rounded-xl shadow-lg shadow-emerald-600/20 outline-none cursor-pointer font-bold appearance-none border-none transition-all"
                            onChange={(e) => {
                                const val = e.target.value;
                                if (val) {
                                    const el = document.getElementById(val);
                                    if (el) {
                                        const offset = 80; // Account for Navbar
                                        const bodyRect = document.body.getBoundingClientRect().top;
                                        const elementRect = el.getBoundingClientRect().top;
                                        const elementPosition = elementRect - bodyRect;
                                        const offsetPosition = elementPosition - offset;

                                        window.scrollTo({
                                            top: offsetPosition,
                                            behavior: 'smooth'
                                        });
                                    }
                                }
                            }}
                        >
                            <option value="" className="bg-white text-slate-800">Seleccionar masa boscosa...</option>
                            {regions.map((item, idx) => (
                                <option key={idx} value={getSlug(item.name)} className="bg-white text-slate-800">
                                    {item.name} {item.type === 'bridge' ? '(Transfronterizo)' : `(${item.country})`}
                                </option>
                            ))}
                        </select>
                    </div>
                </div>
            </div>

            {/* Content Section */}
            <section id="forests-list" className="py-24 bg-slate-50">
                <div className="container mx-auto px-4 max-w-6xl">
                    <div className="space-y-12">
                        {regions.map((item, i) => (
                            item.type === 'country' ? (
                                <div key={i} id={getSlug(item.name)} className={cn(
                                    "flex flex-col md:flex-row gap-12 items-center p-8 bg-white rounded-[2.5rem] border border-slate-100 shadow-sm transition-all duration-500 hover:shadow-xl scroll-mt-24 hover-lift animate-reveal",
                                    i % 4 > 1 ? "md:flex-row-reverse" : ""
                                )} style={{ animationDelay: `${i * 100}ms` }}>
                                    <div className="flex-1 space-y-6">
                                        <div className="flex items-center gap-3">
                                            <span className="w-8 h-1 bg-emerald-500 rounded-full"></span>
                                            <span className="text-emerald-600 font-black tracking-widest uppercase text-xs">
                                                {item.country}
                                            </span>
                                        </div>
                                        <h2 className="text-3xl md:text-4xl font-serif font-bold text-slate-900 leading-tight">
                                            {item.name}
                                        </h2>
                                        <p className="text-lg text-slate-600 leading-relaxed font-light">
                                            {item.desc}
                                        </p>
                                        <div className="flex flex-wrap gap-2 pt-2">
                                            <div className="px-3 py-1 rounded-lg bg-emerald-50 text-emerald-700 text-xs font-bold border border-emerald-100">
                                                {item.status}
                                            </div>
                                        </div>

                                        <div className="pt-4">
                                            <Button 
                                                variant="outline"
                                                className="border-emerald-200 text-emerald-700 hover:bg-emerald-50 rounded-xl px-6 py-2 h-auto text-sm font-bold flex items-center gap-2"
                                                onClick={() => navigate(`/grandes-bosques/historias/${getSlug(item.name)}`)}
                                            >
                                                Ver Historia <ArrowLeft className="h-4 w-4 rotate-180" />
                                            </Button>
                                        </div>
                                    </div>
                                    
                                    <div className="flex-1 w-full max-w-md">
                                        <div className="relative aspect-square rounded-3xl overflow-hidden shadow-lg group parallax-container">
                                            <img 
                                                src={item.img} 
                                                alt={item.name} 
                                                className="absolute inset-0 w-full h-full object-cover transform transition-transform duration-700 group-hover:scale-110 parallax-image" 
                                            />
                                            <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent"></div>
                                        </div>
                                    </div>
                                </div>
                            ) : (
                                <div key={i} id={getSlug(item.name)} className="relative py-8 px-4 flex flex-col items-center text-center scroll-mt-24">
                                    <div className="absolute left-1/2 top-0 bottom-0 w-px bg-slate-200 -z-10 bg-dashed"></div>
                                    <button 
                                        onClick={() => setSelectedBridge(item)}
                                        className="bg-emerald-50 block p-6 rounded-2xl border border-emerald-100 max-w-xl shadow-sm relative group hover:bg-emerald-100 hover:shadow-md transition-all cursor-pointer text-center w-full hover-lift animate-reveal"
                                        style={{ animationDelay: `${i * 100}ms` }}
                                    >
                                        <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-emerald-600 text-white text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest">
                                            {item.countries.length > 2 ? 'Iniciativa Multinacional' : 'Vínculo Transfronterizo'}
                                        </div>
                                        <h3 className="text-xl font-bold text-emerald-900 mb-2 flex items-center justify-center gap-2 group-hover:text-emerald-700 transition-colors">
                                            <Share2 className="h-5 w-5" /> {item.name}
                                        </h3>
                                        <p className="text-sm text-emerald-700/80 leading-relaxed font-medium mb-3 line-clamp-2">
                                            {item.desc}
                                        </p>
                                        <div className="flex items-center justify-center gap-3 flex-wrap">
                                            {item.countries.map((c, index) => (
                                                <React.Fragment key={index}>
                                                    <span className="text-[10px] font-bold text-emerald-600 uppercase tracking-wider">{c}</span>
                                                    {index < item.countries.length - 1 && <div className="h-px w-4 bg-emerald-200"></div>}
                                                </React.Fragment>
                                            ))}
                                        </div>
                                        <div className="mt-4 flex items-center justify-center gap-2 text-[10px] font-bold text-emerald-500 uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity">
                                            <Info className="h-3 w-3" /> Ver detalles
                                        </div>
                                    </button>
                                </div>
                            )
                        ))}
                    </div>
                </div>
            </section>

            {/* CTA */}
            <section className="py-32 bg-emerald-950 text-white text-center px-4 relative overflow-hidden">
                <div className="absolute inset-0 opacity-10 bg-[url('https://images.unsplash.com/photo-1448375240586-dfd8d395ea6c')] bg-fixed bg-cover"></div>
                <div className="relative z-10 max-w-3xl mx-auto space-y-10">
                    <h2 className="text-4xl md:text-5xl font-serif font-black leading-tight">Sea parte de la protección de nuestros pulmones</h2>
                    <p className="text-emerald-200 text-xl font-light">
                        Acceda a los datos abiertos del Observatorio Ambiental para colaborar en la preservación de Centro América y República Dominicana.
                    </p>
                    <div className="flex flex-col sm:flex-row gap-4 justify-center pt-4">
                        <Button 
                            size="lg" 
                            className="bg-white text-emerald-950 hover:bg-emerald-50 px-10 rounded-full font-bold"
                            onClick={() => navigate('/technical/maps')}
                        >
                            Explorar Visor de Mapas
                        </Button>
                        <Button 
                            size="lg" 
                            variant="outline" 
                            className="border-emerald-500 text-emerald-300 hover:bg-emerald-900/50 px-10 rounded-full font-bold"
                            onClick={() => window.location.href = 'mailto:info@sica.int'}
                        >
                            Contáctenos
                        </Button>
                    </div>
                </div>
            </section>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { initParticlesEngine } from "@tsparticles/react";
import { loadSlim } from "@tsparticles/slim";
import { ViewGuideModal } from '../../components/ui/Shared';
import { getEramAxes } from '../../lib/eram';

// Data imports
import { QUESTIONS_DATA } from '../../data/questions';
import CIFRAS_DATA from '../../data/cifras.json';
import { DOCUMENTATION_DATA } from '../../data/documentation';

// Section imports
import { IntroScreen } from './sections/IntroScreen';
import { NavigatorSection } from './sections/NavigatorSection';
import { PreguntasSection } from './sections/PreguntasSection';
import { CifrasSection } from './sections/CifrasSection';
import { MonitoreoSection } from './sections/MonitoreoSection';
import { EjesSection } from './sections/EjesSection';
import { ReportesSection } from './sections/ReportesSection';
import { AnaliticaSection } from './sections/AnaliticaSection';
import { GeoSection } from './sections/GeoSection';
import { VisorSection } from './sections/VisorSection';
import { DocsSection } from './sections/DocsSection';
import { AudienceSection } from './sections/AudienceSection';

export const Home = () => {
  const navigate = useNavigate();
  const [activeRole, setActiveRole] = useState('decision');
  const [isActiveMap, setIsActiveMap] = useState(false);
  const [showIntro, setShowIntro] = useState(true);
  const [isGuideOpen, setIsGuideOpen] = useState(false);
  const [initParticles, setInitParticles] = useState(false);
  const axes = getEramAxes();

  useEffect(() => {
    initParticlesEngine(async (engine) => {
      await loadSlim(engine);
    }).then(() => {
      setInitParticles(true);
    });
  }, []);

  // Filter questions for the home page cards
  const homeQuestions = QUESTIONS_DATA.filter(q =>
    ['forest-loss', 'active-fires', 'drought-risk', 'conservation-30x30', 'water-security', 'ocean-health'].includes(q.id)
  );

  // Get 6 random figures from the data
  const randomCifras = React.useMemo(() => {
    return [...CIFRAS_DATA]
      // eslint-disable-next-line react-hooks/purity
      .sort(() => 0.5 - Math.random())
      .slice(0, 6);
  }, []);

  // Listen for messages from the Navigator Iframe
  React.useEffect(() => {
    const handleMessage = (event) => {
      if (event.data === 'oar-open-guide') {
        setIsGuideOpen(true);
      } else if (event.data === 'oar-scroll-down') {
        const content = document.getElementById('preguntas');
        if (content) content.scrollIntoView({ behavior: 'smooth' });
      } else if (event.data === 'oar-scroll-up') {
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const handleStartConnection = () => {
    const introElem = document.getElementById('intro-screen');
    if (introElem) introElem.style.opacity = '0';
    setTimeout(() => setShowIntro(false), 1000);
  };

  return (
    <div className="flex flex-col min-h-screen bg-white selection:bg-emerald-500 selection:text-white">
      <style>{`
        @keyframes blob-drift {
          0%, 100% { transform: translate(0, 0) scale(1) }
          33% { transform: translate(30px, -50px) scale(1.1) }
          66% { transform: translate(-20px, 20px) scale(0.9) }
        }
        @keyframes mesh-drift {
          from { background-position: 0% 0% }
          to { background-position: 100% 100% }
        }
        @keyframes glow-pulse {
          0%, 100% { box-shadow: 0 0 10px rgba(16,185,129,0.2) }
          50% { box-shadow: 0 0 40px rgba(16,185,129,0.6) }
        }
        @keyframes float-slow {
          0%, 100% { transform: translateY(0) }
          50% { transform: translateY(-10px) }
        }
        @keyframes gradient-move {
          0% { background-position: 0% 50% }
          50% { background-position: 100% 50% }
          100% { background-position: 0% 50% }
        }
        .text-glow {
          text-shadow: 0 0 20px rgba(16,185,129,0.3);
        }
      `}</style>
      <AnimatePresence>
        {showIntro && (
          <IntroScreen 
            key="intro" 
            showIntro={showIntro} 
            handleStartConnection={handleStartConnection} 
            initParticles={initParticles} 
          />
        )}
      </AnimatePresence>
      
      <NavigatorSection />

      <PreguntasSection questions={homeQuestions} navigate={navigate} />

      <CifrasSection cifras={randomCifras} navigate={navigate} />

      <MonitoreoSection navigate={navigate} />

      <EjesSection axes={axes} navigate={navigate} />

      <ReportesSection navigate={navigate} />

      <AnaliticaSection navigate={navigate} />

      <GeoSection navigate={navigate} />

      <VisorSection isActiveMap={isActiveMap} setIsActiveMap={setIsActiveMap} navigate={navigate} />

      <DocsSection documents={DOCUMENTATION_DATA.slice(0, 3)} navigate={navigate} />

      <AudienceSection activeRole={activeRole} setActiveRole={setActiveRole} navigate={navigate} />

      {/* Footer Divider / Context */}
      <div className="max-w-7xl mx-auto px-8 pb-4 mt-6 mb-4">
        <div className="border-t border-slate-200 py-4 text-center text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
          Observatorio Ambiental Regional (OAR) • Estrategia Regional Ambiental de Centroamérica y República Dominicana
        </div>
      </div>

      <ViewGuideModal isOpen={isGuideOpen} onClose={() => setIsGuideOpen(false)} />
    </div>
  );
};

import React from 'react';
import { Database, ArrowRight } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Button } from '../../../components/ui/Shared';

export const AnaliticaSection = ({ navigate }) => {
  const word = "búsqueda".split("");

  return (
    <section id="analitica" className="mt-32 py-24 bg-gradient-to-b from-white via-slate-50 to-slate-100 overflow-hidden relative border-t border-slate-100">
      <div 
        className="absolute top-0 right-0 w-1/3 h-full bg-brand-primary/5 blur-[120px] rounded-full"
        style={{ animation: 'blob-drift 20s infinite' }}
      ></div>

      <div className="container mx-auto px-4 relative z-10">
        <div className="flex flex-col lg:flex-row items-start lg:items-center gap-16 lg:gap-24">
          <motion.div 
            initial={{ opacity: 0, x: -50 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            className="w-full lg:flex-1 space-y-8 relative z-30"
          >
            <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-brand-primary/10 text-brand-primary text-[10px] font-black uppercase tracking-[0.2em] border border-brand-primary/20 shadow-sm">
              <Database className="h-3.5 w-3.5" /> Intelligence Center
            </div>
            <h2 className="text-3xl md:text-6xl font-serif font-black leading-tight text-slate-900">
              Haz tu propia <br />
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-brand-primary to-emerald-600 italic">
                {word.map((char, i) => (
                  <motion.span
                    key={i}
                    initial={{ opacity: 0, y: 10 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.1 }}
                  >
                    {char}
                  </motion.span>
                ))}
              </span>
            </h2>
            <p className="text-slate-600 text-lg md:text-xl font-light leading-relaxed max-w-xl">
              ¿Qué te interesa saber a ti? Explore nuestras bases de datos mediante cruces dinámicos de variables.
            </p>
            <div className="flex flex-wrap gap-6 pt-4">
              <Button
                className="bg-brand-primary text-white hover:bg-brand-primary/90 rounded-full px-6 py-4 md:px-10 md:py-7 h-auto font-black text-sm md:text-base shadow-xl shadow-brand-primary/20 transition-all hover:scale-105 active:scale-95 group overflow-hidden"
                onClick={() => navigate('/analisis-multidimensional')}
              >
                <div className="flex items-center gap-2 relative z-10">
                  Iniciar Análisis <ArrowRight className="h-5 w-5 group-hover:translate-x-2 transition-transform" />
                </div>
              </Button>
            </div>
          </motion.div>

          <div className="w-full lg:flex-1 relative h-[300px] md:h-[500px]">
            <div className="absolute inset-0 flex items-center justify-center">
              <motion.div 
                initial={{ opacity: 0, scale: 0.8 }}
                whileInView={{ opacity: 1, scale: 1 }}
                viewport={{ once: true }}
                className="relative w-full max-w-md aspect-square"
              >
                <motion.div 
                  animate={{ y: [0, -20, 0] }}
                  transition={{ duration: 5, repeat: Infinity, ease: "easeInOut" }}
                  className="absolute top-10 left-0 p-6 bg-white/60 backdrop-blur-xl rounded-[2.5rem] border border-white shadow-2xl rotate-[-6deg] hover:rotate-0 transition-all duration-700 z-20 group cursor-pointer"
                >
                  <div className="h-20 w-40 md:h-24 md:w-48 flex items-end gap-2 pt-6">
                    <motion.div 
                      animate={{ height: ["40%", "100%", "40%"] }} 
                      transition={{ duration: 3, repeat: Infinity }}
                      className="flex-1 bg-brand-primary/60 rounded-t-xl shadow-lg shadow-brand-primary/20"
                    ></motion.div>
                    <motion.div 
                      animate={{ height: ["30%", "60%", "30%"] }} 
                      transition={{ duration: 4, repeat: Infinity }}
                      className="flex-1 bg-brand-primary/30 rounded-t-xl"
                    ></motion.div>
                    <motion.div 
                      animate={{ height: ["60%", "85%", "60%"] }} 
                      transition={{ duration: 2.5, repeat: Infinity }}
                      className="flex-1 bg-brand-primary/80 rounded-t-xl shadow-lg shadow-brand-primary/40"
                    ></motion.div>
                  </div>
                  <div className="mt-4 flex justify-between">
                    <div className="h-2 w-12 bg-slate-200 rounded-full"></div>
                    <div className="h-2 w-8 bg-slate-100 rounded-full"></div>
                  </div>
                </motion.div>
                <div 
                  className="absolute inset-0 bg-brand-primary/10 rounded-full blur-[100px] pointer-events-none"
                  style={{ animation: 'blob-drift 15s infinite' }}
                ></div>
              </motion.div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

import React from 'react';
import { Users, BarChart3, Globe, ArrowRight } from 'lucide-react'; 
import { motion, AnimatePresence } from 'framer-motion';
import { Button } from '../../../components/ui/Shared';
import { cn } from '../../../lib/utils';

export const AudienceSection = ({ activeRole, setActiveRole, navigate }) => {
  return (
    <section className="py-24 bg-slate-50 relative overflow-hidden">
      {/* Decorative Blobs */}
      <div 
        className="absolute top-0 left-0 w-[500px] h-[500px] bg-emerald-500/5 blur-[120px] rounded-full -ml-64 -mt-64 pointer-events-none"
        style={{ animation: 'blob-drift 20s infinite' }}
      />

      <div className="container mx-auto px-4 relative z-10">
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="text-center max-w-3xl mx-auto mb-20"
        >
          <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-100 text-emerald-700 text-[10px] font-black uppercase tracking-widest mb-6 shadow-sm">
            <Users className="h-3 w-3" /> Adaptación de Usuario
          </div>
          <h2 className="text-3xl md:text-5xl font-serif font-black text-slate-900 leading-tight mb-6">Plataforma <span className="text-emerald-600 italic text-glow">Adaptativa</span></h2>
          <p className="text-slate-600 text-lg md:text-xl font-light leading-relaxed">
            Hemos diseñado flujos de trabajo específicos para cada actor clave en la gestión ambiental regional, asegurando que cada dato llegue con el propósito correcto.
          </p>
        </motion.div>

        <div className="flex flex-wrap justify-center gap-4 mb-16">
          {[
            { id: 'decision', label: 'Dashboard', icon: Users },
            { id: 'tech', label: 'Visor Interactivo', icon: BarChart3 },
            { id: 'citizen', label: 'Historias', icon: Globe }
          ].map((role) => (
            <motion.button
              key={role.id}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => setActiveRole(role.id)}
              className={cn(
                "flex items-center gap-3 px-8 py-4 rounded-full font-black uppercase text-[10px] tracking-widest transition-all shadow-xl",
