import React, { useState, useMemo, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Search, Globe, ShieldAlert, Leaf, BookOpen, Target, BarChart3, Info, X, MapPin, Activity, CalendarDays, TrendingUp, TableProperties, Database, Scale, ClipboardList, Trees } from 'lucide-react';
import { indicatorsData } from '../../data/indicators';
import { RegionalEvolutionChart } from '../../components/monitoring/RegionalChart';
import { Card, Button, Badge, Input } from '../../components/ui/Shared';

const generateMockData = (indicator) => {
    const countries = ["Belice", "Costa Rica", "El Salvador", "Guatemala", "Honduras", "Nicaragua", "Panamá", "Rep. Dominicana"];
    const mainMetric = indicator.metrics[0];
    const unit = mainMetric.unit;
    const isPercentage = unit.includes('%');
    const isIndex = unit.includes('Índice');
    const isSummable = !isPercentage && !isIndex;
    const startYear = 2015;
    const endYear = 2025;
    const years = Array.from({ length: endYear - startYear + 1 }, (_, i) => startYear + i);
    let allData = [];
    countries.forEach(c => {
        let baseVal = isPercentage ? (Math.random() * 30 + 10) :
            isIndex ? (Math.random() * 0.4 + 0.4) :
                (Math.random() * 800 + 50);
        let trend = (Math.random() - 0.2) * (isPercentage ? 1.5 : isIndex ? 0.01 : 20);
        years.forEach(y => {
            let val = baseVal + trend * (y - startYear) + (Math.random() * (isPercentage ? 2 : isIndex ? 0.01 : 15) - (isPercentage ? 1 : isIndex ? 0.005 : 7.5));
            if (isPercentage) val = Math.max(0, Math.min(100, val));
            if (isIndex) val = Math.max(0, Math.min(1, val));
            if (!isPercentage && !isIndex) val = Math.max(0, val);
            allData.push({
                country: c,
                year: y,
                value: isIndex ? Number(val.toFixed(3)) : Number(val.toFixed(1)),
                unit: unit
            });
        });
    });
    return { data: allData, years, isSummable, unit };
};

export const StrategicMonitoring = () => {
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedCategory, setSelectedCategory] = useState('Todas');
    const [activeIndicator, setActiveIndicator] = useState(null);
    const [activeDataView, setActiveDataView] = useState(null);
    const [selectedType, setSelectedType] = useState('Todas');
    const [selectedYear, setSelectedYear] = useState(2024);

    const availableCategories = useMemo(() => {
        const filteredByType = selectedType === 'Todas' 
            ? indicatorsData 
            : indicatorsData.filter(item => item.type === selectedType);
        return ['Todas', ...new Set(filteredByType.map(item => item.category))];
    }, [selectedType]);

    const availableTypes = useMemo(() => {
        const filteredByCategory = selectedCategory === 'Todas'
            ? indicatorsData
            : indicatorsData.filter(item => item.category === selectedCategory);
        return ['Todas', ...new Set(filteredByCategory.map(item => item.type))];
    }, [selectedCategory]);

    useEffect(() => {
        if (!availableCategories.includes(selectedCategory)) {
            setSelectedCategory('Todas');
        }
    }, [availableCategories, selectedCategory]);

    useEffect(() => {
        if (!availableTypes.includes(selectedType)) {
            setSelectedType('Todas');
        }
    }, [availableTypes, selectedType]);

    const filteredIndicators = useMemo(() => {
        return indicatorsData.filter(indicator => {
            const matchesSearch = indicator.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                indicator.metrics.some(m => m.variable.toLowerCase().includes(searchTerm.toLowerCase())) ||
                indicator.id.toLowerCase().includes(searchTerm.toLowerCase());
            const matchesCategory = selectedCategory === 'Todas' || indicator.category === selectedCategory;
            const matchesType = selectedType === 'Todas' || indicator.type === selectedType;
            return matchesSearch && matchesCategory && matchesType;
        });
    }, [searchTerm, selectedCategory, selectedType]);

    const counts = useMemo(() => {
        return {
            total: filteredIndicators.length,
            impacto: filteredIndicators.filter(i => i.type === 'impacto').length,
            gestion: filteredIndicators.filter(i => i.type === 'gestion').length,
            synergies: [...new Set(filteredIndicators.flatMap(i => i.synergies))].length
        };
    }, [filteredIndicators]);

    const dataset = useMemo(() => {
        if (!activeDataView) return null;
        return generateMockData(activeDataView);
    }, [activeDataView]);

    const { regionalData, currentYearData } = useMemo(() => {
        if (!dataset) return { regionalData: [], currentYearData: [] };
        const regional = dataset.years.map(y => {
            const yearRecords = dataset.data.filter(d => d.year === y);
            const sum = yearRecords.reduce((acc, curr) => acc + curr.value, 0);
            const val = dataset.isSummable ? sum : (sum / yearRecords.length);
            return {
                year: y,
                value: Number(val.toFixed(dataset.unit.includes('Índice') ? 3 : 1))
            };
        });
        const current = dataset.data
            .filter(d => d.year === selectedYear)
            .sort((a, b) => b.value - a.value);
        return { regionalData: regional, currentYearData: current };
    }, [dataset, selectedYear]);

    const getSynergyColor = (synergy) => {
        switch (synergy) {
            case 'CDB': return 'bg-emerald-100 text-emerald-800 border-emerald-200';
            case 'CMNUCC': return 'bg-blue-100 text-blue-800 border-blue-200';
            case 'CNULD': return 'bg-amber-100 text-amber-800 border-amber-200';
            default: return 'bg-gray-100 text-gray-800';
        }
    };

    const getCategoryIcon = (category) => {
        switch (category) {
            case 'Objetivos Globales': return <Globe className="w-5 h-5 text-indigo-500" />;
            case 'Metas de Reducción de Amenazas': return <ShieldAlert className="w-5 h-5 text-red-500" />;
            case 'Metas de Uso Sostenible y Beneficios': return <Leaf className="w-5 h-5 text-green-500" />;
            case 'Herramientas y Soluciones': return <BookOpen className="w-5 h-5 text-blue-500" />;
            default: return <Target className="w-5 h-5" />;
        }
    };

    return (
        <div className="min-h-screen bg-slate-50 pb-20">
            {/* HEADER */}
            <header className="bg-indigo-900 text-white shadow-lg sticky top-0 z-40">
                <div className="max-w-7xl mx-auto px-4 py-6 flex flex-col sm:flex-row justify-between items-center gap-6">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-700 p-2.5 rounded-xl shadow-inner text-white flex items-center justify-center">
                            <Globe className="w-8 h-8" />
                        </div>
                        <div className="text-left">
                            <h1 className="text-xl md:text-2xl font-black leading-tight uppercase tracking-tight">Monitoreo Estratégico</h1>
                            <div className="flex items-center gap-2">
                                <p className="text-indigo-200 text-xs font-bold uppercase tracking-widest">SICA | Sinergias Convenciones de Río</p>
                                <Link to="/monitoring/operational" className="bg-indigo-700/50 hover:bg-indigo-600 px-3 py-1 rounded text-[10px] font-black uppercase transition-all flex items-center gap-1.5 ml-2">
                                    <Trees className="w-3 h-3" /> Ver Operativo
                                </Link>
                            </div>
                        </div>
                    </div>
                    <div className="w-full sm:w-80">
                        <Input
                            icon={Search}
                            placeholder="Buscar indicador..."
                            className="bg-indigo-950/50 border-indigo-700 text-white placeholder-indigo-400 focus:ring-indigo-400 focus:border-indigo-400"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                </div>
            </header>

            <main className="max-w-7xl mx-auto px-4 py-8">
                {/* NARRATIVE ORIENTATION */}
                <div className="mb-10 p-8 bg-indigo-50/50 rounded-[2rem] border border-indigo-100 flex gap-6 items-start">
                    <div className="p-4 bg-indigo-600 rounded-2xl text-white shadow-lg shrink-0">
                        <Info className="w-6 h-6" />
                    </div>
                    <div className="text-left">
                        <h3 className="text-xl font-bold text-indigo-900 mb-2 font-serif">Sobre el Monitoreo Estratégico</h3>
                        <p className="text-slate-600 leading-relaxed font-light">
                            En esta vista, usted encontrará los **Indicadores de Impacto** que miden el estado real del medio ambiente en la región centroamericana (ej. cobertura forestal, biodiversidad, GEI). Estos datos están alineados con las **Convenciones de Río** y reflejan el éxito de las políticas regionales a largo plazo.
                        </p>
                    </div>
                </div>

                {/* FILTROS */}
                <div className="mb-10 flex flex-col md:flex-row gap-8 items-start md:items-center bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                    <div className="flex flex-col gap-3 flex-1">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest text-left">Filtrar por Categoría</span>
                        <div className="flex flex-wrap gap-2">
                            {availableCategories.map(cat => (
                                <button
                                    key={cat}
                                    onClick={() => setSelectedCategory(cat)}
                                    className={`px-5 py-2.5 rounded-full text-xs font-black uppercase tracking-widest transition-all ${
                                        selectedCategory === cat
                                            ? 'bg-indigo-600 text-white shadow-lg scale-105'
                                            : 'bg-slate-50 text-slate-500 border border-slate-200 hover:bg-indigo-50 hover:text-indigo-700'
                                    }`}
                                >
                                    {cat}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="flex flex-col gap-3">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest text-left">Tipología</span>
                        <div className="flex gap-2">
                            {availableTypes.map(type => (
                                <button
                                    key={type}
                                    onClick={() => setSelectedType(type)}
                                    className={`px-5 py-2.5 rounded-full text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${
                                        selectedType === type
                                            ? (type === 'impacto' ? 'bg-blue-600 text-white shadow-lg' : type === 'gestion' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-800 text-white shadow-lg')
                                            : 'bg-white text-slate-500 border border-slate-200 hover:bg-slate-50'
                                    }`}
                                >
                                    {type === 'Todas' ? 'Todas' : type === 'impacto' ? <><Target className="w-4 h-4" /> Impacto</> : <><ClipboardList className="w-4 h-4" /> Gestión</>}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                {/* KPI DASHBOARD */}
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
                    <Card 
                        onClick={() => { setSelectedCategory('Todas'); setSelectedType('Todas'); setSearchTerm(''); }}
                        className="bg-indigo-50 border-indigo-100 p-6 rounded-[2rem] hover:shadow-md transition-all cursor-pointer group"
                    >
                        <div className="flex items-center gap-4">
                            <div className="bg-indigo-600 p-3 rounded-2xl text-white group-hover:scale-110 transition-transform">
                                <BarChart3 className="w-6 h-6" />
                            </div>
                            <div className="text-left">
                                <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Total Indicadores</p>
                                <div className="flex items-baseline gap-2">
                                    <h3 className="text-3xl font-black text-indigo-900">{counts.total}</h3>
                                </div>
                            </div>
                        </div>
                    </Card>

                    <Card 
                        onClick={() => setSelectedType('impacto')}
                        className={`p-6 rounded-[2rem] transition-all cursor-pointer border-2 ${selectedType === 'impacto' ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-blue-50 text-slate-600 hover:bg-blue-50'}`}
                    >
                        <div className="flex items-center gap-4">
                            <div className={`${selectedType === 'impacto' ? 'bg-white/20' : 'bg-blue-100'} p-3 rounded-2xl ${selectedType === 'impacto' ? 'text-white' : 'text-blue-600'}`}>
                                <Target className="w-6 h-6" />
                            </div>
                            <div className="text-left">
                                <p className={`text-[10px] font-black uppercase tracking-widest ${selectedType === 'impacto' ? 'text-blue-100' : 'text-blue-400'}`}>Impacto</p>
                                <h3 className={`text-3xl font-black ${selectedType === 'impacto' ? 'text-white' : 'text-slate-800'}`}>{counts.impacto}</h3>
                            </div>
                        </div>
                    </Card>

                    <Card 
                        onClick={() => setSelectedType('gestion')}
                        className={`p-6 rounded-[2rem] transition-all cursor-pointer border-2 ${selectedType === 'gestion' ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-emerald-50 text-slate-600 hover:bg-emerald-50'}`}
                    >
                        <div className="flex items-center gap-4">
                            <div className={`${selectedType === 'gestion' ? 'bg-white/20' : 'bg-emerald-100'} p-3 rounded-2xl ${selectedType === 'gestion' ? 'text-white' : 'text-emerald-600'}`}>
                                <ClipboardList className="w-6 h-6" />
                            </div>
                            <div className="text-left">
                                <p className={`text-[10px] font-black uppercase tracking-widest ${selectedType === 'gestion' ? 'text-emerald-100' : 'text-emerald-400'}`}>Gestión</p>
                                <h3 className={`text-3xl font-black ${selectedType === 'gestion' ? 'text-white' : 'text-slate-800'}`}>{counts.gestion}</h3>
                            </div>
                        </div>
                    </Card>

                    <Card className="bg-white border-slate-100 p-6 rounded-[2rem] shadow-sm">
                        <div className="flex items-center gap-4">
                            <div className="bg-amber-100 p-3 rounded-2xl text-amber-600">
                                <Activity className="w-6 h-6" />
                            </div>
                            <div className="text-left">
                                <p className="text-[10px] font-black text-amber-500 uppercase tracking-widest">Sinergias Río</p>
                                <h3 className="text-3xl font-black text-slate-800">{counts.synergies}</h3>
                            </div>
                        </div>
                    </Card>
                </div>

                {/* GRID */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {filteredIndicators.map((indicator, idx) => (
                        <Card key={idx} className="bg-white rounded-[1.5rem] shadow-sm border border-slate-100 overflow-hidden flex flex-col h-full hover:shadow-xl transition-all group">
                            <div className="p-8 flex-grow">
                                <div className="flex items-center justify-between mb-4">
                                    <div className="flex items-center gap-2">
                                        {getCategoryIcon(indicator.category)}
                                        <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                                            {indicator.id}
                                        </span>
                                    </div>
                                    <Badge className={`px-2 py-0.5 rounded text-[8px] font-black uppercase tracking-tighter ${
                                        indicator.type === 'impacto' 
                                        ? 'bg-blue-50 text-blue-600 border-blue-100' 
                                        : 'bg-emerald-50 text-emerald-600 border-emerald-100'
                                    }`}>
                                        {indicator.type === 'impacto' ? 'Impacto' : 'Gestión'}
                                    </Badge>
                                </div>
                                <h3 className="text-xl font-bold text-slate-900 leading-tight mb-4 group-hover:text-indigo-700 transition-colors">
                                    {indicator.title}
                                </h3>
                                <div className="flex flex-wrap gap-1.5 mb-6">
                                    {indicator.synergies.map((syn) => (
                                        <span key={syn} className={`px-2.5 py-1 rounded-md text-[9px] font-black border uppercase tracking-tighter ${getSynergyColor(syn)}`}>
                                            {syn}
                                        </span>
                                    ))}
                                </div>
                                <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                                    <p className="text-xs text-slate-500 font-bold uppercase tracking-wider mb-1">Variable Principal</p>
                                    <p className="text-sm text-slate-700 font-medium line-clamp-2">
                                        {indicator.metrics[0].variable}
                                    </p>
                                </div>
                            </div>
                            
                            <div className="flex border-t border-slate-50 bg-slate-50/50">
                                <button
                                    onClick={() => { setActiveDataView(indicator); setSelectedYear(2024); }}
                                    className="flex-1 py-4 px-4 flex justify-center items-center gap-2 text-xs font-black uppercase tracking-widest text-blue-600 hover:bg-blue-50 transition-all border-r border-slate-100"
                                >
                                    <BarChart3 className="w-4 h-4" /> Ver Datos
                                </button>
                                <button
                                    onClick={() => setActiveIndicator(indicator)}
                                    className="flex-1 py-4 px-4 flex justify-center items-center gap-2 text-xs font-black uppercase tracking-widest text-indigo-600 hover:bg-indigo-50 transition-all"
                                >
                                    <Info className="w-4 h-4" /> Abrir Ficha
                                </button>
                            </div>
                        </Card>
                    ))}
                </div>
            </main>

            {/* MODAL: FICHA TÉCNICA */}
            {activeIndicator && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setActiveIndicator(null)}></div>
                    <Card className="relative bg-white rounded-[2rem] shadow-2xl w-full max-w-3xl max-h-[90vh] flex flex-col overflow-hidden p-0 border-none">
                        <div className="flex items-start justify-between p-8 border-b border-slate-100 bg-indigo-50/30">
                            <div>
                                <Badge className="bg-indigo-100 text-indigo-700 border-indigo-200 px-3 py-1 mb-3 font-black uppercase text-[10px]">
                                    {activeIndicator.category} • Metodología
                                </Badge>
                                <h2 className="text-2xl md:text-3xl font-black text-slate-900">{activeIndicator.title}</h2>
                            </div>
                            <button onClick={() => setActiveIndicator(null)} className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-full transition-all">
                                <X className="w-6 h-6" />
                            </button>
                        </div>
                        
                        <div className="p-8 overflow-y-auto space-y-8 flex-1 custom-scrollbar">
                            {activeIndicator.metrics.map((metric, index) => (
                                <div key={index} className="space-y-6">
                                    <div className="flex items-center gap-3 pb-4 border-b border-slate-100">
                                        <div className="p-2 bg-indigo-100 rounded-lg text-indigo-600">
                                            <Target className="w-6 h-6" />
                                        </div>
                                        <h4 className="text-xl font-bold text-slate-800">{metric.variable}</h4>
                                    </div>
                                    
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                        <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100">
                                            <h5 className="flex items-center gap-2 text-[10px] font-black uppercase text-slate-400 mb-4 tracking-widest leading-none">
                                                <Scale className="w-4 h-4" /> Unidad de Medida
                                            </h5>
                                            <span className="text-lg font-black text-slate-800">{metric.unit}</span>
                                        </div>
                                        <div className="bg-amber-50/30 p-6 rounded-2xl border border-amber-100">
                                            <h5 className="flex items-center gap-2 text-[10px] font-black uppercase text-amber-700 mb-4 tracking-widest leading-none">
                                                <Activity className="w-4 h-4" /> Método de Cálculo
                                            </h5>
                                            <p className="text-sm text-slate-700 leading-relaxed font-medium">{metric.method}</p>
                                        </div>
                                    </div>

                                    <div className="bg-blue-50/30 p-6 rounded-2xl border border-blue-100">
                                        <h5 className="flex items-center gap-2 text-[10px] font-black uppercase text-blue-800 mb-6 tracking-widest leading-none">
                                            <Database className="w-4 h-4" /> Fuentes de Datos Sugeridas
                                        </h5>
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                            {metric.sources.national && (
                                                <div className="space-y-2">
                                                    <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest flex items-center gap-1.5">
                                                        <MapPin className="w-3.5 h-3.5"/> Nivel Nacional
                                                    </span>
                                                    <p className="text-sm text-slate-600 leading-relaxed font-medium">{metric.sources.national}</p>
                                                </div>
                                            )}
                                            {metric.sources.regional && (
                                                <div className="space-y-2">
                                                    <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest flex items-center gap-1.5">
                                                        <Globe className="w-3.5 h-3.5"/> Nivel Regional
                                                    </span>
                                                    <p className="text-sm text-slate-600 leading-relaxed font-medium">{metric.sources.regional}</p>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </Card>
                </div>
            )}

            {/* MODAL: DASHBOARD DE DATOS */}
            {activeDataView && dataset && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setActiveDataView(null)}></div>
                    <Card className="relative bg-slate-50 rounded-[2.5rem] shadow-2xl w-full max-w-6xl max-h-[95vh] flex flex-col overflow-hidden p-0 border-none">
                        <div className="flex items-start justify-between p-8 border-b border-slate-200 bg-white">
                            <div className="text-left">
                                <Badge className="bg-blue-100 text-blue-800 border-blue-200 px-3 py-1 mb-3 font-black uppercase text-[10px] tracking-widest">
                                    <Activity className="w-4 h-4 mr-1.5 inline" /> Dashboard Analítico • SICA
                                </Badge>
                                <h2 className="text-2xl md:text-3xl font-black text-slate-900">{activeDataView.title}</h2>
                                <p className="text-sm text-slate-500 mt-2 font-medium">Variable: <span className="text-slate-800 font-bold">{activeDataView.metrics[0].variable}</span></p>
                            </div>
                            <button onClick={() => setActiveDataView(null)} className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-full transition-all">
                                <X className="w-6 h-6" />
                            </button>
                        </div>

                        <div className="p-8 overflow-y-auto space-y-8 flex-1 custom-scrollbar">
                            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                                <div className="space-y-6">
                                    <Card className="p-6 border-slate-200 rounded-2xl shadow-sm bg-white">
                                        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 mb-6 leading-none">
                                            <CalendarDays className="w-4 h-4 text-blue-500" /> Historial Temporal
                                        </h3>
                                        <div className="flex justify-between items-end mb-4">
                                            <span className="text-lg font-bold text-slate-400 leading-none">{dataset.years[0]}</span>
                                            <span className="text-4xl font-black text-blue-600 leading-none">{selectedYear}</span>
                                            <span className="text-lg font-bold text-slate-400 leading-none">{dataset.years[dataset.years.length - 1]}</span>
                                        </div>
                                        <input
                                            type="range"
                                            min={dataset.years[0]}
                                            max={dataset.years[dataset.years.length - 1]}
                                            step="1"
                                            value={selectedYear}
                                            onChange={(e) => setSelectedYear(Number(e.target.value))}
                                            className="w-full h-2 bg-blue-100 rounded-lg appearance-none cursor-pointer accent-blue-600"
                                        />
                                        <p className="text-[10px] font-black uppercase text-slate-400 mt-4 text-center tracking-tighter">Desliza para actualizar el año</p>
                                    </Card>

                                    <Card className="bg-gradient-to-br from-blue-600 to-indigo-700 p-8 rounded-2xl shadow-xl border-none text-white relative overflow-hidden flex flex-col justify-center">
                                        <div className="absolute top-0 right-0 -mt-8 -mr-8 text-white/10">
                                            <Globe className="w-48 h-48" />
                                        </div>
                                        <h3 className="text-[10px] font-black uppercase tracking-widest text-blue-200 flex items-center gap-2 mb-4 leading-none relative z-10">
                                            <TrendingUp className="w-4 h-4" /> Agregado Regional SICA
                                        </h3>
                                        <div className="relative z-10 flex items-baseline gap-2">
                                            <span className="text-5xl font-black tracking-tighter">
                                                {regionalData.find(d => d.year === selectedYear)?.value.toLocaleString() || 0}
                                            </span>
                                            <span className="text-xl font-bold text-blue-200">
                                                {dataset.unit}
                                            </span>
                                        </div>
                                        <p className="text-xs font-medium text-blue-100 mt-4 relative z-10 opacity-80">
                                            {dataset.isSummable ? "Sumatoria Total Regional" : "Promedio Ponderado Regional"}
                                        </p>
                                    </Card>
                                </div>

                                <div className="lg:col-span-2">
                                    <RegionalEvolutionChart
                                        data={regionalData}
                                        selectedYear={selectedYear}
                                        onSelectYear={setSelectedYear}
                                        unit={dataset.unit}
                                        isSummable={dataset.isSummable}
                                    />
                                </div>
                            </div>

                            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                                <Card className="p-8 border-slate-200 rounded-2xl shadow-sm bg-white">
                                    <h3 className="text-lg font-black text-slate-900 mb-8 flex items-center gap-2">
                                        <BarChart3 className="w-6 h-6 text-blue-500" /> Distribución por País ({selectedYear})
                                    </h3>
                                    <div className="space-y-5">
                                        {currentYearData.map((d, i) => {
                                            const maxVal = Math.max(...currentYearData.map(item => item.value));
                                            const widthPercent = (d.value / (maxVal || 1)) * 100;
                                            return (
                                                <div key={i} className="flex items-center gap-4">
                                                    <div className="w-32 text-xs font-black text-slate-500 text-right uppercase tracking-tighter truncate">{d.country}</div>
                                                    <div className="flex-1 h-3 bg-slate-100 rounded-full relative overflow-hidden">
                                                        <div
                                                            className="absolute top-0 left-0 h-full bg-blue-500 rounded-full transition-all duration-700 ease-out"
                                                            style={{ width: `${widthPercent}%` }}
                                                        ></div>
                                                    </div>
                                                    <div className="w-20 text-sm font-black text-slate-900 text-left">
                                                        {d.value.toLocaleString()}
                                                    </div>
                                                </div>
                                            )
                                        })}
                                    </div>
                                </Card>

                                <Card className="p-0 border-slate-200 rounded-2xl shadow-sm bg-white overflow-hidden flex flex-col">
                                    <div className="p-6 border-b border-slate-100 bg-slate-50/50">
                                        <h3 className="text-lg font-black text-slate-900 flex items-center gap-2">
                                            <TableProperties className="w-6 h-6 text-emerald-500" /> Registros Detallados
                                        </h3>
                                    </div>
                                    <div className="overflow-x-auto">
                                        <table className="w-full text-left text-sm">
                                            <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-100">
                                                <tr>
                                                    <th className="px-6 py-4">País</th>
                                                    <th className="px-6 py-4">Año</th>
                                                    <th className="px-6 py-4 text-right">Valor</th>
                                                    <th className="px-6 py-4">Unidad</th>
                                                </tr>
                                            </thead>
                                            <tbody className="divide-y divide-slate-50">
                                                {currentYearData.map((d, i) => (
                                                    <tr key={i} className="hover:bg-slate-50 transition-colors group">
                                                        <td className="px-6 py-4 font-bold text-slate-900">{d.country}</td>
                                                        <td className="px-6 py-4 text-slate-500 font-medium">{d.year}</td>
                                                        <td className="px-6 py-4 text-right font-black text-blue-600">{d.value.toLocaleString()}</td>
                                                        <td className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-tighter">{d.unit}</td>
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                    </div>
                                </Card>
                            </div>
                        </div>
                    </Card>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, AreaChart, Area
} from 'recharts';
import { Flame, AlertTriangle, RefreshCw, ArrowLeft, ArrowDown, Share2, Download, TrendingUp, MapPin, HelpCircle, Map as MapIcon, ChevronRight, Database, ExternalLink, ShieldAlert, Activity, Bell } from 'lucide-react';
import { Card, Button, Badge, DataSourceModal, ShareButton } from '../../../components/ui/Shared';
import { useNavigate, useSearchParams } from 'react-router-dom';

import { MiniMap } from '../../../components/map/MiniMap';
import { SICA_COORDINATES } from '../../../data/constants';

const FIRE_POINTS = [
    { lat: 17.5, lon: -90.5, country: 'GT', popup: 'Peten, Guatemala (Alta Confianza)' },
    { lat: 15.5, lon: -89.0, country: 'GT', popup: 'Sierra de las Minas, Guatemala' },
    { lat: 14.8, lon: -87.0, country: 'HN', popup: 'Olancho, Honduras' },
    { lat: 13.5, lon: -85.5, country: 'NI', popup: 'Bosawas, Nicaragua' },
    { lat: 9.5, lon: -83.5, country: 'CR', popup: 'Talamanca, Costa Rica' },
    { lat: 8.5, lon: -80.0, country: 'PA', popup: 'Darien, Panama' },
    { lat: 17.0, lon: -88.5, country: 'BZ', popup: 'Chiquibul, Belize' },
    { lat: 18.5, lon: -70.5, country: 'DO', popup: 'Cordillera Central, Rep. Dom.' }
];

// --- COMPONENTES AUXILIARES ---

const StatCard = ({ title, value, unit, colorClass, subtitle, icon: Icon, delay = 0 }) => (
    <motion.div
        initial={{ opacity: 0, y: 20 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
        transition={{ delay }}
        whileHover={{ y: -8 }}
        className="h-full"
    >
        <Card className={`bg-white/80 backdrop-blur-xl p-6 md:p-8 border-t-4 ${colorClass} shadow-xl shadow-slate-200/50 hover:shadow-2xl transition-all rounded-[2.5rem] relative overflow-hidden h-full flex flex-col group`}>
            <div className="flex justify-between items-start mb-6">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{title}</h4>
                {Icon && <Icon className="h-5 w-5 text-slate-200 transition-colors group-hover:text-orange-500" />}
            </div>
            <div className="flex items-baseline gap-2 mb-4">
                <span className="text-3xl md:text-4xl font-black text-slate-900 tracking-tighter">
                    {new Intl.NumberFormat('es-GT').format(value)}
                </span>
                <span className="text-sm font-bold text-slate-500">{unit}</span>
            </div>
            <p className="text-sm text-slate-500 leading-relaxed font-light">{subtitle}</p>
        </Card>
    </motion.div>
);

export const AnswerActiveFires = () => {
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();
    const selectedIso = searchParams.get("country") || "regional";
    const [data, setData] = useState(null);
    const [loading, setLoading] = useState(true);
    const [showHelp, setShowHelp] = useState(false);

    const dataSources = [
        { name: "Alertas de Incendio", description: "Detecciones de anomalías térmicas (incendios activos) en tiempo real vía satélite.", provider: "NASA FIRMS (MODIS/VIIRS)", updateFrequency: "Tiempo Real" },
        { name: "Área Quemada", description: "Estimación de superficie afectada por incendios.", provider: "GWIS (Global Wildfire Info System)", updateFrequency: "Mensual" }
    ];

    useEffect(() => {
        setLoading(true);
        const remoteUrl = `https://raw.githubusercontent.com/mapgisdev/prototipo_oar/main/public/api/fires_data.json`;

        fetch(remoteUrl)
            .then(res => res.json())
            .then(allData => {
                setData(allData[selectedIso] || allData['regional']);
                setLoading(false);
            })
            .catch(err => {
                console.error("Error fetching remote fires data:", err);
                setLoading(false);
            });
    }, [selectedIso]);

    const countryName = SICA_COORDINATES[selectedIso]?.name || (selectedIso === 'regional' ? "Región SICA" : "Guatemala");
    const mapView = SICA_COORDINATES[selectedIso] || SICA_COORDINATES['regional'];

    // Filtro de Puntos
    const activePoints = selectedIso === 'regional'
        ? FIRE_POINTS
        : FIRE_POINTS.filter(p => p.country === selectedIso);

    // Mapeo para visualización (color rojo)
    const mapMarkers = activePoints.map(p => ({ ...p, type: 'circle', color: '#EF4444' }));

    // Simular carga al cambiar país
    const handleCountryChange = (e) => {
        setLoading(true);
        setSearchParams({ country: e.target.value });
        setTimeout(() => setLoading(false), 500);
    };

    return (
        <div className="relative min-h-screen bg-slate-50 overflow-hidden selection:bg-orange-500 selection:text-white">
            <style>{`
                @keyframes blob-drift {
                    0%, 100% { transform: translate(0, 0) scale(1) }
                    33% { transform: translate(40px, -60px) scale(1.1) }
                    66% { transform: translate(-30px, 30px) scale(0.9) }
                }
                .text-glow-orange {
                    text-shadow: 0 0 20px rgba(249,115,22,0.3);
                }
                .mesh-fire {
                    background-image: radial-gradient(circle at 20% 20%, rgba(249, 115, 22, 0.05) 0%, transparent 50%),
                                      radial-gradient(circle at 80% 80%, rgba(239, 68, 68, 0.05) 0%, transparent 50%);
                }
            `}</style>

            {/* Background Decorative Elements */}
            <div className="absolute inset-0 mesh-fire pointer-events-none z-0" />
            <div 
                className="absolute top-0 right-0 w-[800px] h-[800px] bg-orange-500/5 blur-[120px] rounded-full -mr-64 -mt-64 pointer-events-none z-0"
                style={{ animation: 'blob-drift 30s infinite alternate' }}
            />
            <div 
                className="absolute bottom-0 left-0 w-[600px] h-[600px] bg-red-500/5 blur-[120px] rounded-full -ml-64 -mb-64 pointer-events-none z-0"
                style={{ animation: 'blob-drift 25s infinite alternate-reverse' }}
            />

            {/* HEADER INTERACTIVO */}
            <header className="sticky top-0 z-[100] bg-white/70 backdrop-blur-xl border-b border-slate-200/50 shadow-sm">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                        <motion.div
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="flex items-center gap-4"
                        >
                            <Button 
                                variant="ghost" 
                                size="sm" 
                                onClick={() => navigate('/strategic-questions')}
                                className="rounded-full h-10 w-10 p-0 hover:bg-slate-100 transition-colors"
                            >
                                <ArrowLeft className="h-5 w-5 text-slate-400" />
                            </Button>
                            <div>
                                <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">
                                    <Bell className="h-3.5 w-3.5 text-orange-500 animate-pulse" />
                                    Vigilancia de Incendios en Tiempo Real
                                </div>
                                <div className="flex items-center gap-3">
                                    <div className="relative group">
                                        <select
                                            className="appearance-none bg-transparent text-xl md:text-3xl font-serif font-black text-slate-900 cursor-pointer pr-10 focus:outline-none hover:text-orange-600 transition-colors"
                                            value={selectedIso}
                                            onChange={handleCountryChange}
                                        >
                                            {Object.entries(SICA_COORDINATES).filter(([k]) => k !== 'regional').map(([code, val]) => (
                                                <option key={code} value={code}>{val.name}</option>
                                            ))}
                                            <option value="regional">Región SICA (Total)</option>
                                        </select>
                                        <ArrowDown className="h-4 w-4 text-slate-400 absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none group-hover:text-orange-600 transition-colors" />
                                    </div>
                                    <Badge className="hidden md:flex bg-orange-500 text-white border-none px-3 py-1 text-[10px] font-black uppercase tracking-widest animate-pulse">
                                        NASA FIRMS VIIRS
                                    </Badge>
                                </div>
                            </div>
                        </motion.div>

                        <motion.div 
                            initial={{ opacity: 0, x: 20 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="flex items-center gap-3"
                        >
                            <Button onClick={() => setShowHelp(true)} variant="outline" className="rounded-full h-12 w-12 p-0 border-slate-200 hover:bg-slate-900 hover:text-white transition-all shadow-sm">
                                <HelpCircle className="h-5 w-5" />
                            </Button>
                            <ShareButton />
                            <Button className="bg-slate-900 text-white rounded-full px-8 h-12 font-black uppercase text-[10px] tracking-widest group shadow-xl hover:shadow-slate-900/20 transition-all">
                                <Download className="h-4 w-4 mr-2" /> Descargar <span className="hidden sm:inline ml-1">Informe</span>
                            </Button>
                        </motion.div>
                    </div>
                </div>
            </header>

            <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 relative z-10">
                <div className="space-y-16">
                    {/* MAP SECTION */}
                    <motion.div
                        initial={{ opacity: 0, scale: 0.98 }}
                        whileInView={{ opacity: 1, scale: 1 }}
                        viewport={{ once: true }}
                    >
                        <Card className="p-0 overflow-hidden border border-slate-200/50 shadow-2xl rounded-[4rem] group relative">
                            <div className="h-[400px] md:h-[550px] relative">
                                <MiniMap
                                    markers={mapMarkers}
                                    center={[mapView.lat, mapView.lon]}
                                    zoom={mapView.zoom}
                                />
                                <div className="absolute top-8 left-8 z-[1000] flex flex-col gap-3">
                                    <Badge className="bg-white/95 backdrop-blur-md text-orange-600 border-none px-5 py-2.5 text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center gap-2">
                                        <div className="h-2 w-2 rounded-full bg-orange-500 animate-ping" />
                                        Anomalías Térmicas Activas
                                    </Badge>
                                    <Badge className="bg-slate-900/90 backdrop-blur-md text-white border-none px-5 py-2.5 text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center gap-2">
                                        <ShieldAlert className="h-3.5 w-3.5 text-orange-400" />
                                        VIIRS 375m • Landsat-8
                                    </Badge>
                                </div>
                                <div className="absolute bottom-8 right-8 z-[1000]">
                                    <Button className="bg-white/90 backdrop-blur-md text-slate-900 border border-slate-200 rounded-2xl px-6 h-12 flex items-center gap-2 shadow-2xl hover:bg-slate-900 hover:text-white transition-all">
                                      <Activity className="h-4 w-4" /> Ver Capas de Emergencia
                                    </Button>
                                </div>
                            </div>
                            <div className="p-8 bg-white/90 backdrop-blur-xl border-t border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
                                <div className="flex items-center gap-4">
                                    <div className="p-3 bg-orange-50 rounded-2xl border border-orange-100">
                                        <MapIcon className="h-5 w-5 text-orange-600" />
                                    </div>
                                    <div>
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Localización Geoespacial</p>
                                        <p className="text-sm font-bold text-slate-900">Interacción directa con focos detectados en el último ciclo orbital.</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-2 px-6 py-2 bg-slate-900 text-white rounded-full text-[10px] font-black uppercase tracking-widest">
                                    <RefreshCw className="h-3.5 w-3.5 animate-spin text-orange-500" /> Sincronizado en Tiempo Real
                                </div>
                            </div>
                        </Card>
                    </motion.div>

                    {/* NARRATIVA DINÁMICA */}
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                    >
                        <Card className="p-6 md:p-12 bg-white/70 backdrop-blur-2xl border border-slate-100 shadow-2xl shadow-orange-500/5 rounded-[3.5rem] relative overflow-hidden group">
                            <div className="absolute top-0 right-0 p-12 opacity-[0.03] group-hover:opacity-[0.08] transition-opacity pointer-events-none">
                                <Flame className="h-64 w-64 text-orange-600" />
                            </div>
                            <div className="relative z-10 flex flex-col lg:flex-row lg:items-center justify-between gap-12">
                                <div className="max-w-3xl">
                                    <h3 className="text-[10px] font-black text-orange-600 uppercase tracking-[0.4em] mb-6 flex items-center gap-3">
                                        <div className="w-12 h-0.5 bg-orange-200" />
                                        Estado Crítico de Situación
                                    </h3>
                                    {data ? (
                                        <div className="space-y-6">
                                            <p className="text-slate-900 text-2xl md:text-4xl font-serif leading-tight">
                                                Durante las últimas 24 horas, <span className="text-orange-600 font-black italic">{countryName}</span> ha registrado un total de <span className="underline decoration-orange-500/30 decoration-8 underline-offset-[-2px]">{data.alerts} focos activos</span>. 
                                            </p>
                                            <p className="text-xl text-slate-500 leading-relaxed font-light">
                                                De estos, un preocupante <strong className="text-slate-900 font-black">{Math.round((data.highConfidence/data.alerts)*100)}%</strong> corresponden a alertas de alta confianza, confirmando actividad de fuego persistente en áreas boscosas primarias.
                                            </p>
                                        </div>
                                    ) : (
                                        <div className="space-y-6">
                                            <div className="h-10 bg-slate-100 animate-pulse rounded-full w-full"></div>
                                            <div className="h-10 bg-slate-100 animate-pulse rounded-full w-2/3"></div>
                                        </div>
                                    )}
                                </div>
                                <div className="flex flex-col gap-4 shrink-0">
                                    <Button 
                                        className="rounded-2xl px-10 h-16 bg-orange-600 text-white hover:bg-orange-700 transition-all font-black text-[10px] uppercase tracking-widest shadow-xl shadow-orange-600/20"
                                        onClick={() => navigate('/emergency')}
                                    >
                                        Puesto de Mando Regional <ChevronRight className="ml-2 h-4 w-4" />
                                    </Button>
                                    <span className="text-center text-[10px] font-black text-slate-400 uppercase tracking-widest">Protocolo de Respuesta Activo</span>
                                </div>
                            </div>
                        </Card>
                    </motion.div>

                    {/* KPI CARDS */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                        <StatCard
                            title="Total Alertas (24h)"
                            value={data?.alerts || 0}
                            unit="detecciones"
                            subtitle="Suma total de anomalías térmicas procesadas vía satélite."
                            colorClass="border-t-orange-500"
                            icon={Flame}
                            delay={0}
                        />
                        <StatCard
                            title="Superficie Afectada"
                            value={data?.area || 0}
                            unit="ha"
                            subtitle="Estimación de área con probabilidad de combustión activa."
                            colorClass="border-t-red-600"
                            icon={AlertTriangle}
                            delay={0.1}
                        />
                        <StatCard
                            title="Huella de Carbono"
                            value={Math.round((data?.alerts || 0) * 0.12)}
                            unit="tCO2e"
                            subtitle="Estimación de gases liberados por biomasa incinerada."
                            colorClass="border-t-slate-800"
                            icon={TrendingUp}
                            delay={0.2}
                        />
                    </div>

                    {/* CHARTS & METADATA SECTION */}
                    <div className="grid grid-cols-1 lg:grid-cols-5 gap-8 items-stretch">
                        <div className="lg:col-span-3">
                            <motion.div
                                initial={{ opacity: 0, scale: 0.98 }}
                                whileInView={{ opacity: 1, scale: 1 }}
                                viewport={{ once: true }}
                            >
                                <Card className="p-6 md:p-12 bg-white border border-slate-100 shadow-2xl rounded-[3.5rem] h-[400px] md:h-[580px] flex flex-col group">
                                    <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-12 gap-6">
                                        <div>
                                            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] mb-3">Dinámica Temporal</h3>
                                            <p className="text-2xl font-serif font-black text-slate-900 tracking-tight">Evolución de Alertas por Día</p>
                                        </div>
                                        <div className="flex items-center gap-3 px-5 py-2.5 bg-orange-50 text-orange-600 rounded-3xl border border-orange-100 text-[10px] font-black uppercase tracking-widest shadow-sm">
                                            <Activity className="h-4 w-4 animate-pulse" /> Ciclo de 7 Días
                                        </div>
                                    </div>
                                    <div className="flex-1 w-full min-h-0 relative">
                                        <ResponsiveContainer width="100%" height="100%">
                                            <AreaChart data={data?.trend || []} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                                                <defs>
                                                    <linearGradient id="colorFire" x1="0" y1="0" x2="0" y2="1">
                                                        <stop offset="5%" stopColor="#F97316" stopOpacity={0.4} />
                                                        <stop offset="95%" stopColor="#F97316" stopOpacity={0} />
                                                    </linearGradient>
                                                </defs>
                                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                                <XAxis dataKey="d" axisLine={false} tickLine={false} tick={{ fill: '#94a3b8', fontSize: 10, fontWeight: 'black' }} />
                                                <YAxis axisLine={false} tickLine={false} tick={{ fill: '#94a3b8', fontSize: 10, fontWeight: 'black' }} />
                                                <Tooltip 
                                                    contentStyle={{ 
                                                        borderRadius: '24px', 
                                                        border: 'none', 
                                                        boxShadow: '0 25px 60px rgba(0,0,0,0.1)',
                                                        padding: '20px',
                                                        background: 'rgba(255,255,255,0.95)',
                                                        backdropFilter: 'blur(15px)'
                                                    }} 
                                                />
                                                <Area 
                                                    type="monotone" 
                                                    dataKey="v" 
                                                    stroke="#F97316" 
                                                    strokeWidth={5} 
                                                    fillOpacity={1} 
                                                    fill="url(#colorFire)" 
                                                    animationDuration={2000}
                                                />
                                            </AreaChart>
                                        </ResponsiveContainer>
                                    </div>
                                    <div className="mt-8 pt-8 border-t border-slate-50 flex items-center justify-center gap-8 text-[10px] font-black uppercase tracking-widest text-slate-400">
                                        <div className="flex items-center gap-2"><div className="h-2.5 w-2.5 rounded-full bg-orange-500" /> Focos Satelitales</div>
                                        <div className="flex items-center gap-2"><div className="h-2.5 w-2.5 rounded-full bg-slate-200" /> Histórico SICA</div>
                                    </div>
                                </Card>
                            </motion.div>
                        </div>

                        <motion.div
                            initial={{ opacity: 0, x: 20 }}
                            whileInView={{ opacity: 1, x: 0 }}
                            viewport={{ once: true }}
                            className="lg:col-span-2"
                        >
                            <Card className="p-12 bg-slate-900 text-white shadow-2xl rounded-[3.5rem] h-full relative overflow-hidden group">
                                <div className="absolute top-0 right-0 p-12 opacity-5 scale-150 group-hover:scale-125 transition-transform duration-1000">
                                    <Database className="h-64 w-64 text-white" />
                                </div>
                                <div className="relative z-10 space-y-12">
                                    <div>
                                        <h3 className="text-[10px] font-black text-orange-400 uppercase tracking-[0.4em] mb-12 flex items-center gap-3">
                                            <div className="w-10 h-0.5 bg-orange-500/30" />
                                            Sistemas de Inteligencia
                                        </h3>
                                        <div className="space-y-8">
                                            <div className="group/item">
                                                <div className="flex items-center gap-4 mb-4">
                                                    <div className="h-10 w-10 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-center group-hover/item:bg-orange-500 transition-colors">
                                                        <Activity className="h-5 w-5 text-orange-400 group-hover/item:text-white" />
                                                    </div>
                                                    <span className="text-sm font-black uppercase tracking-[0.2em]">Sensor VIIRS S-NPP</span>
                                                </div>
                                                <p className="text-sm text-slate-400 leading-relaxed font-light">
                                                    Detección espacial de 375m. Optimizado para capturar anomalías térmicas pequeñas y incendios de baja intensidad en dosel cerrado.
                                                </p>
                                            </div>

                                            <div className="group/item">
                                                <div className="flex items-center gap-4 mb-4">
                                                    <div className="h-10 w-10 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-center group-hover/item:bg-blue-500 transition-colors">
                                                        <RefreshCw className="h-5 w-5 text-blue-400 group-hover/item:text-white" />
                                                    </div>
                                                    <span className="text-sm font-black uppercase tracking-[0.2em]">NASA FIRMS Pipeline</span>
                                                </div>
                                                <p className="text-sm text-slate-400 leading-relaxed font-light">
                                                    Procesamiento automatizado NRT (Near Real Time) con una latencia inferior a las 3 horas desde el paso del satélite.
                                                </p>
                                            </div>
                                        </div>
                                    </div>
                                    <Button className="w-full rounded-2xl h-16 bg-white text-slate-900 hover:bg-orange-500 hover:text-white transition-all font-black text-[10px] uppercase tracking-widest shadow-2xl">
                                        Consola Técnica FIRMS <ExternalLink className="ml-2 h-4 w-4" />
                                    </Button>
                                </div>
                            </Card>
                        </motion.div>
                    </div>
                </div>
            </main>

            <footer className="max-w-7xl mx-auto px-8 py-20 relative z-10 font-bold text-[10px] uppercase tracking-[0.3em] text-slate-400 flex flex-col md:flex-row justify-between items-center gap-8 border-t border-slate-200/50">
                <div className="flex items-center gap-6">
                    <span>© 2026 Observatorio Ambiental Regional</span>
                    <div className="h-1.5 w-1.5 rounded-full bg-orange-500 animate-pulse" />
                    <span>Protocolo SICA SAT-Incendios</span>
                </div>
                <div className="flex gap-8 items-center opacity-70">
                    <div className="flex items-center gap-2">
                      <span className="text-slate-300">Latencia:</span> ~3.2h Regional
                    </div>
                    <div className="flex items-center gap-2">
                      <span className="text-slate-300">Nodos:</span> 8 Regionales Activos
                    </div>
                </div>
            </footer>

            <DataSourceModal
                isOpen={showHelp}
                onClose={() => setShowHelp(false)}
                title="Sistemas de Monitoreo de Incendios"
                sources={dataSources}
            />
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend } from 'recharts';
import { Shield, Leaf, AlertCircle, Info, ArrowLeft, ArrowDown, Share2, Download, TrendingUp, Target, HelpCircle, Loader2, Database, Map as MapIcon, ChevronRight } from 'lucide-react';
import { Card, Badge, Button, DataSourceModal, ShareButton } from '../../../components/ui/Shared';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { MiniMap } from '../../../components/map/MiniMap';
import { SICA_COORDINATES } from '../../../data/constants';
import { cn } from '../../../lib/utils';

// Eliminadas constantes locales para usar fetch remoto

const StatCard = ({ title, value, unit, colorClass, subtitle, icon: Icon, delay = 0 }) => (
    <motion.div
        initial={{ opacity: 0, y: 20 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
        transition={{ delay }}
        whileHover={{ y: -8 }}
        className="h-full"
    >
        <Card className={`bg-white/80 backdrop-blur-xl p-8 border-t-4 ${colorClass} shadow-xl shadow-slate-200/50 hover:shadow-2xl transition-all rounded-[2.5rem] relative overflow-hidden h-full flex flex-col`}>
            <div className="flex justify-between items-start mb-6">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{title}</h4>
                <div className={`p-2 rounded-xl bg-slate-50 border border-slate-100`}>
                    {Icon && <Icon className="h-5 w-5 text-slate-400" />}
                </div>
            </div>
            <div className="flex items-baseline gap-2 mb-4">
                <span className="text-4xl font-black text-slate-900 tracking-tighter">
                    {value}
                </span>
