                                <div className="flex gap-6 items-center bg-slate-50 px-6 py-3 rounded-3xl border border-slate-100">
                                    <div className="flex items-center gap-3">
                                        <div className="w-2.5 h-2.5 rounded-full bg-orange-500 shadow-lg shadow-orange-500/30" />
                                        <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Temperatura</span>
                                    </div>
                                    <div className="h-4 w-px bg-slate-200" />
                                    <div className="flex items-center gap-3">
                                        <div className="w-2.5 h-2.5 rounded-full bg-blue-500 shadow-lg shadow-blue-500/30" />
                                        <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Lluvia</span>
                                    </div>
                                </div>
                            </div>
                            <div className="flex-1 w-full min-h-0 relative">
                                {loading ? (
                                    <div className="h-full flex flex-col items-center justify-center gap-6">
                                        <div className="relative">
                                            <Loader2 className="animate-spin h-14 w-14 text-orange-200" />
                                            <BarChart3 className="absolute inset-0 m-auto h-6 w-6 text-orange-500" />
                                        </div>
                                        <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-300 animate-pulse">Procesando Reanálisis Global ERA-5...</span>
                                    </div>
                                ) : (
                                    <ResponsiveContainer width="100%" height="100%">
                                        <ComposedChart data={data} margin={{ top: 0, right: 0, bottom: 0, left: -20 }}>
                                            <defs>
                                                <linearGradient id="colorRain" x1="0" y1="0" x2="0" y2="1">
                                                    <stop offset="5%" stopColor="#3B82F6" stopOpacity={0.4}/>
                                                    <stop offset="95%" stopColor="#3B82F6" stopOpacity={0}/>
                                                </linearGradient>
                                            </defs>
                                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                            <XAxis 
                                                dataKey="date" 
                                                minTickGap={40} 
                                                axisLine={false} 
                                                tickLine={false} 
                                                tick={{ fill: '#94a3b8', fontSize: 10, fontWeight: 'black', textTransform: 'uppercase' }} 
                                            />
                                            <YAxis 
                                                yAxisId="left" 
                                                orientation="left" 
                                                axisLine={false}
                                                tickLine={false}
                                                tick={{ fill: '#F97316', fontSize: 10, fontWeight: 'black' }}
                                            />
                                            <YAxis 
                                                yAxisId="right" 
                                                orientation="right" 
                                                axisLine={false}
                                                tickLine={false}
                                                tick={{ fill: '#3B82F6', fontSize: 10, fontWeight: 'black' }}
                                            />
                                            <Tooltip 
                                                contentStyle={{ 
                                                    borderRadius: '24px', 
                                                    border: 'none', 
                                                    boxShadow: '0 25px 60px rgba(0,0,0,0.1)',
                                                    padding: '20px',
                                                    background: 'rgba(255,255,255,0.95)',
                                                    backdropFilter: 'blur(15px)'
                                                }} 
                                            />
                                            <Area 
                                                yAxisId="right" 
                                                type="monotone" 
                                                dataKey="rain" 
                                                name="Lluvia (mm)" 
                                                fill="url(#colorRain)" 
                                                stroke="#3B82F6" 
                                                strokeWidth={3}
                                                animationDuration={2000}
                                            />
                                            <Line 
                                                yAxisId="left" 
                                                type="monotone" 
                                                dataKey="temp" 
                                                name="Temperatura (°C)" 
                                                stroke="#F97316" 
                                                strokeWidth={5} 
                                                dot={false}
                                                activeDot={{ r: 8, strokeWidth: 0, fill: '#F97316' }}
                                                animationDuration={1500}
                                            />
                                        </ComposedChart>
                                    </ResponsiveContainer>
                                )}
                            </div>
                            <div className="mt-8 flex justify-center items-center gap-10">
                                <div className="flex flex-col items-center gap-1">
                                    <span className="text-2xl font-black text-slate-900 tracking-tighter">{summary.temp}°C</span>
                                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Máximo Hoy</span>
                                </div>
                                <div className="h-10 w-px bg-slate-100" />
                                <div className="flex flex-col items-center gap-1">
                                    <span className="text-2xl font-black text-slate-900 tracking-tighter">{summary.rain}mm</span>
                                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Acumulado Trimestre</span>
                                </div>
                            </div>
                        </Card>
                    </motion.div>
                </div>
            </main>

            <footer className="max-w-7xl mx-auto px-8 py-20 relative z-10 font-bold text-[10px] uppercase tracking-[0.3em] text-slate-400 flex flex-col md:flex-row justify-between items-center gap-8 border-t border-slate-200/50">
                <div className="flex items-center gap-6">
                    <span>© 2026 Observatorio Ambiental Regional</span>
                    <div className="h-1.5 w-1.5 rounded-full bg-orange-500 animate-pulse" />
                    <span>Conexión Nodo Copernicus CDS</span>
                </div>
                <div className="flex gap-8 items-center opacity-70">
                    <span className="hover:text-orange-500 cursor-pointer transition-colors border-b border-transparent hover:border-orange-500">ERA5 Reanalysis</span>
                    <span className="hover:text-orange-500 cursor-pointer transition-colors border-b border-transparent hover:border-orange-500">Open-Meteo V3</span>
                    <div className="p-2 bg-white rounded-xl shadow-sm border border-slate-100">
                      <ShieldAlert className="h-4 w-4 text-orange-500" />
                    </div>
                </div>
            </footer>

            <DataSourceModal
                isOpen={showHelp}
                onClose={() => setShowHelp(false)}
                title="Sistemas de Monitoreo Climático y Riesgo"
                sources={dataSources}
            />
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
    LineChart, Line, Cell
} from 'recharts';
import { ArrowDown, Share2, Download, Leaf, AlertTriangle, TrendingUp, MapPin, ArrowLeft, HelpCircle, ChevronRight, Map as MapIcon, Database, ExternalLink, Loader2 } from 'lucide-react';
import { Card, Button, Badge, DataSourceModal, ShareButton } from '../../../components/ui/Shared';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { MiniMap } from '../../../components/map/MiniMap';
import { SICA_COORDINATES } from '../../../data/constants';

// --- COMPONENTES AUXILIARES ---

const StatCard = ({ title, value, unit, colorClass, subtitle, icon: Icon, delay = 0 }) => (
    <motion.div
        initial={{ opacity: 0, y: 20 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
        transition={{ delay }}
        whileHover={{ y: -8 }}
        className="h-full"
    >
        <Card className={`bg-white/80 backdrop-blur-xl p-8 border-t-4 ${colorClass} shadow-xl shadow-slate-200/50 hover:shadow-2xl transition-all rounded-[2.5rem] relative overflow-hidden h-full flex flex-col`}>
            <div className="flex justify-between items-start mb-6">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{title}</h4>
                {Icon && <Icon className="h-5 w-5 text-slate-200" />}
            </div>
            <div className="flex items-baseline gap-2 mb-4">
                <span className="text-4xl font-black text-slate-900 tracking-tighter">
                    {value ? new Intl.NumberFormat('es-GT').format(value) : '0'}
                </span>
                <span className="text-sm font-bold text-slate-500">{unit}</span>
            </div>
            <p className="text-sm text-slate-500 leading-relaxed font-light">{subtitle}</p>
        </Card>
    </motion.div>
);

export const AnswerForestLoss = () => {
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();
    const selectedIso = searchParams.get("country") || "regional";
    const [showHelp, setShowHelp] = useState(false);
    const [data, setData] = useState(null);
    const [loading, setLoading] = useState(true);

    const dataSources = [
        { name: "Pérdida de Cobertura Arbórea", description: "Identifica la eliminación de la cubierta vegetal (dosel > 30%) mediante satélites Landsat.", provider: "Hansen/UMD/Google/USGS/NASA", updateFrequency: "Anual" },
        { name: "Emisiones de CO₂", description: "Estimación de emisiones de carbono por pérdida de biomasa arbórea superficial.", provider: "Global Forest Watch", updateFrequency: "Anual" },
        { name: "Alertas GLAD", description: "Sistema de alerta temprana de deforestación basado en imágenes satelitales.", provider: "GLAD Lab (UMD)", updateFrequency: "Semanal" }
    ];

    const countryName = SICA_COORDINATES[selectedIso]?.name || (selectedIso === 'regional' ? 'Región SICA' : 'Guatemala');
    const mapView = SICA_COORDINATES[selectedIso] || SICA_COORDINATES['regional'];

    useEffect(() => {
        setLoading(true);
        const remoteUrl = `https://raw.githubusercontent.com/mapgisdev/prototipo_oar/main/public/api/forest_data.json`;

        fetch(remoteUrl)
            .then(res => res.json())
            .then(allData => {
                setData(allData[selectedIso] || allData['regional']);
                setLoading(false);
            })
            .catch(err => {
                console.error("Error fetching remote data:", err);
                setLoading(false);
            });
    }, [selectedIso]);

    const stats = useMemo(() => {
        if (!data) return { topRegion: { name: '...', percent: 0 }, totalLoss: 0, percentLoss: 0 };
        const topRegion = data.topRegions?.[0] || { name: 'Múltiples zonas', percent: 0, value: 0 };
        const totalLoss = data.lossTotal || 0;
        const treeCoverRef = data.treeCover || 1;
        const percentLoss = ((totalLoss / treeCoverRef) * 100).toFixed(1);

        return { topRegion, totalLoss, percentLoss };
    }, [data]);

    const kFormatter = (num) => {
        return Math.abs(num) > 999
            ? Math.sign(num) * ((Math.abs(num) / 1000).toFixed(1)) + 'k'
            : Math.sign(num) * Math.abs(num);
    };

    const fmt = (num) => new Intl.NumberFormat('es-GT').format(num);

    const handleCountryChange = (e) => {
        setLoading(true);
        setSearchParams({ country: e.target.value });
        setTimeout(() => setLoading(false), 500);
    };

    return (
        <div className="relative min-h-screen bg-slate-50 overflow-hidden selection:bg-[#FE6598] selection:text-white">
            <style>{`
                @keyframes blob-drift {
                    0%, 100% { transform: translate(0, 0) scale(1) }
                    33% { transform: translate(40px, -60px) scale(1.1) }
                    66% { transform: translate(-30px, 30px) scale(0.9) }
                }
                .text-glow-red {
                    text-shadow: 0 0 20px rgba(254,101,152,0.3);
                }
            `}</style>

            {/* Background Decorative Elements */}
            <div 
                className="absolute top-0 right-0 w-[600px] h-[600px] bg-[#FE6598]/5 blur-[120px] rounded-full -mr-64 -mt-64 pointer-events-none z-0"
                style={{ animation: 'blob-drift 25s infinite alternate' }}
            />
            <div 
                className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-amber-500/5 blur-[120px] rounded-full -ml-64 -mb-64 pointer-events-none z-0"
                style={{ animation: 'blob-drift 20s infinite alternate-reverse' }}
            />

            {/* HEADER INTERACTIVO */}
            <header className="sticky top-0 z-[100] bg-white/70 backdrop-blur-xl border-b border-slate-200/50 shadow-sm">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                        <motion.div
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="flex items-center gap-4"
                        >
                            <Button 
                                variant="ghost" 
                                size="sm" 
