                            colorClass="border-t-emerald-500"
                            icon={AlertTriangle}
                            delay={0.1}
                        />
                        <StatCard
                            title="Huella de Carbono"
                            value={data?.co2Emissions || 0}
                            unit="Mt CO₂"
