                    text-shadow: 0 0 20px rgba(59,130,246,0.3);
                }
            `}</style>

            {/* Background Decorative Elements */}
            <div 
                className="absolute top-0 right-0 w-[600px] h-[600px] bg-blue-500/5 blur-[120px] rounded-full -mr-64 -mt-64 pointer-events-none z-0"
