                                                }`}
                                            >
                                                {m === 'sum' ? 'Suma' : m === 'avg' ? 'Prom' : 'Rec'}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        </Card>
                    </div>

                    {/* Chart Area */}
